            padding: '4rem 2rem'
        }}>
            <div className="container" style={{ maxWidth: '1200px', margin: '0 auto' }}>

                {/* Header Section */}
                <div style={{ marginBottom: '3rem', borderLeft: '4px solid #6366f1', paddingLeft: '1.5rem' }}>
                    <h1 style={{
                        fontSize: '2.2rem',
                        fontWeight: 850,
                        marginBottom: '0.5rem',
                        color: '#fff',
                        letterSpacing: '-1px'
