import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Search, BookOpen, Target, FileText, Cpu, Brain, Award, ChevronRight, Sparkles, Terminal, Filter, Play } from 'lucide-react';
import axios from 'axios';
import './Dashboard.css';

const Dashboard = () => {
    const navigate = useNavigate();
    const [searchQuery, setSearchQuery] = useState('');
    const [userData, setUserData] = useState(null);
    const [domains, setDomains] = useState([]);
    const [tutorials, setTutorials] = useState([]);
    const [placeholder, setPlaceholder] = useState('');
    const [isDeleting, setIsDeleting] = useState(false);
    const [loopNum, setLoopNum] = useState(0);
    const [typingSpeed, setTypingSpeed] = useState(150);

    const words = ["Learn Python", "Learn DSA", "Learn Web Dev", "Learn Cyber Security", "Learn Machine Learning"];

    useEffect(() => {
        const handleTyping = () => {
            const i = loopNum % words.length;
            const fullWord = words[i];

            setPlaceholder(isDeleting
                ? fullWord.substring(0, placeholder.length - 1)
                : fullWord.substring(0, placeholder.length + 1)
            );

            setTypingSpeed(isDeleting ? 75 : 150);

            if (!isDeleting && placeholder === fullWord) {
                setTimeout(() => setIsDeleting(true), 2000);
            } else if (isDeleting && placeholder === '') {
                setIsDeleting(false);
                setLoopNum(loopNum + 1);
            }
        };

        const timer = setTimeout(handleTyping, typingSpeed);
        return () => clearTimeout(timer);
    }, [placeholder, isDeleting, loopNum, typingSpeed]);

    useEffect(() => {
        const fetchData = async () => {
            try {
                const profileRes = await axios.get(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/users/profile`, {
                    headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
                });
                setUserData(profileRes.data);

                const [domainsRes, tutorialsRes] = await Promise.all([
                    axios.get(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/domains`),
                    axios.get(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/tutorials`, {
                        headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
                    })
                ]);
                setDomains(domainsRes.data);
                setTutorials(tutorialsRes.data);
            } catch (err) {
                console.error("Dashboard data fetch error:", err);
            }
        };
        fetchData();
    }, []);

    const handleSearch = (e) => {
        e.preventDefault();
        // Redirect to learning or specific search results if implemented
        navigate(`/learning`);
    };

    return (
        <div className="dashboard-container animate-fade-in">
            {/* Hero Section */}
            <header className="dashboard-hero">
                <div className="section-container">
                    <h1>Hello, What Do You Want To Learn?</h1>

                    <div className="search-container">
                        <form onSubmit={handleSearch} className="gfg-search-bar">
                            <input
                                type="text"
                                placeholder={placeholder + (placeholder ? "|" : "Learn...")}
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                style={{ textAlign: 'left' }}
                            />
                        </form>
                    </div>

                    <div className="search-badges">
                        {(domains.length > 0 ? domains.slice(0, 5).map(d => d.name) : ['DSA Online', 'Master DS & ML', 'Full Stack Dev', 'Cyber Security', 'DevOps']).map(tag => (
                            <span key={tag} className="search-badge" onClick={() => navigate(`/domain/${tag}`)}>{tag}</span>
                        ))}
                    </div>
                </div>
            </header>

            <div className="section-container">
                {/* Premium AI Career Journey Banner */}
                <div className="promotional-banner">
                    <div className="promo-content">
                        <h2>Propel Your Career <br /> with Dev2Dev AI</h2>
                        <p>Master the skills that matter. Land the job you deserve. Our AI-driven paths provide the unfair advantage you need in today's tech world.</p>
                        <div style={{ marginTop: '2rem' }}>
                            <button onClick={() => navigate('/learning')} className="btn-brand" style={{ background: 'var(--gfg-brand)', border: 'none', color: '#fff', padding: '1rem 2.5rem', borderRadius: '12px', fontWeight: '800', cursor: 'pointer', fontSize: '1.05rem', boxShadow: '0 10px 20px rgba(99, 102, 241, 0.3)' }}>Resume Your AI Path</button>
                        </div>
                    </div>

                    <div className="promo-steps">
                        <div className="promo-card">
                            <div className="icon-box"><Brain size={20} /></div>
                            <h4>Precision Roadmaps</h4>
                            <p>AI-curated topics tailored specifically to your dream role.</p>
                        </div>
                        <div className="promo-card">
                            <div className="icon-box"><Target size={20} /></div>
                            <h4>Job Readiness</h4>
                            <p>Real-time stats on your interview and coding performance.</p>
                        </div>
                        <div className="promo-card">
                            <div className="icon-box"><Award size={20} /></div>
                            <h4>Elite Certification</h4>
                            <p>Validate your expertise with industry-recognized mocks.</p>
                        </div>
                    </div>
                </div>

                {/* Dashboard Content Grid */}
                <div className="dashboard-sections">
                    <main className="main-column">
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                            <h2 style={{ fontSize: '1.5rem', fontWeight: '800' }}>Recommended for You</h2>
                            <button onClick={() => navigate('/onboarding')} style={{ background: 'transparent', border: 'none', color: 'var(--gfg-brand)', fontWeight: 'bold', cursor: 'pointer' }}>Explore All <ChevronRight size={16} /></button>
                        </div>

                        <div className="dashboard-grid">
                            {domains.slice(0, 4).map(domain => (
                                <div key={domain._id} className="course-card" onClick={() => navigate(`/domain/${domain.name}`)}>
                                    <div className="course-img">
                                        {domain.name.includes('AI') ? <Cpu /> : <Terminal />}
                                    </div>
                                    <div className="course-info">
                                        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
                                            <span className="badge-tag">Self-Paced</span>
                                            <span style={{ fontSize: '0.75rem', color: '#f1c40f', fontWeight: 'bold' }}>⭐ Premium</span>
                                        </div>
                                        <h3>{domain.name}</h3>
                                        <p style={{ fontSize: '0.85rem', color: 'var(--gfg-text-muted)', marginBottom: '1rem' }}>Master {domain.name} with AI-curated roadmaps and projects.</p>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', color: 'var(--gfg-brand)', fontSize: '0.9rem', fontWeight: 'bold' }}>
                                            View Roadmap <ChevronRight size={14} />
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </main>

                    <aside className="sidebar-column">
                        <div className="sidebar-card">
                            <h4>Current Progress</h4>
                            {userData?.selectedDomain ? (
                                <div>
                                    <p style={{ fontWeight: '600', marginBottom: '0.5rem' }}>{userData.selectedDomain}</p>
                                    <div style={{ height: '8px', background: 'rgba(255,255,255,0.05)', borderRadius: '4px', overflow: 'hidden', marginBottom: '0.5rem' }}>
                                        <div style={{ height: '100%', width: `${userData.progressPercentage || 0}%`, background: 'var(--gfg-brand)', transition: 'width 1s ease-in-out' }}></div>
                                    </div>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.75rem', marginBottom: '1rem', opacity: 0.6 }}>
                                        <span>Progress</span>
                                        <span>{userData.progressPercentage || 0}%</span>
                                    </div>
                                    <button onClick={() => navigate('/learning')} className="btn-outline" style={{ width: '100%', fontSize: '0.8rem', padding: '0.5rem' }}>Continue Learning</button>
                                </div>
                            ) : (
                                <div style={{ textAlign: 'center', padding: '1rem' }}>
                                    <p style={{ fontSize: '0.9rem', color: 'var(--gfg-text-muted)', marginBottom: '1rem' }}>No active track found.</p>
                                    <button onClick={() => navigate('/onboarding')} className="btn-brand" style={{ background: 'var(--gfg-brand)', color: '#fff', border: 'none', padding: '0.5rem 1rem', borderRadius: '4px', cursor: 'pointer' }}>Start Onboarding</button>
                                </div>
                            )}
                        </div>

                        <div className="sidebar-card animate-slide-up" style={{ animationDelay: '0.1s' }}>
                            <h4>Recent Performance</h4>
                            {userData?.examScores?.length > 0 ? (
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                        <span style={{ fontSize: '0.85rem', opacity: 0.7 }}>Last Exam:</span>
                                        <span style={{ fontWeight: '700', color: userData.examScores[userData.examScores.length - 1].passed ? '#818cf8' : '#ef4444', fontSize: '0.9rem' }}>
                                            {userData.examScores[userData.examScores.length - 1].score}/{userData.examScores[userData.examScores.length - 1].totalMarks}
                                        </span>
                                    </div>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                        <span style={{ fontSize: '0.85rem', opacity: 0.7 }}>Avg. Accuracy:</span>
                                        <span style={{ fontWeight: '700', color: 'var(--gfg-brand)', fontSize: '0.9rem' }}>{userData.avgScore}%</span>
                                    </div>
                                    <button onClick={() => navigate('/exams')} className="btn-outline" style={{ width: '100%', fontSize: '0.75rem', padding: '0.4rem', marginTop: '0.25rem' }}>View All Results</button>
                                </div>
                            ) : (
                                <div style={{ textAlign: 'center', padding: '0.5rem' }}>
                                    <p style={{ fontSize: '0.8rem', color: 'var(--gfg-text-muted)', marginBottom: '0.75rem' }}>Take your first exam to see stats.</p>
                                    <button onClick={() => navigate('/exams')} className="btn-brand" style={{ background: 'var(--gfg-brand)', color: '#fff', border: 'none', padding: '0.4rem 0.8rem', borderRadius: '4px', cursor: 'pointer', fontSize: '0.8rem' }}>Browse Exams</button>
                                </div>
                            )}
                        </div>

                        <div className="sidebar-card">
                            <h4>Quick Actions</h4>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                                <div onClick={() => navigate('/exams')} style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', cursor: 'pointer', padding: '0.4rem' }} className="hover-nav">
                                    <Award size={18} color="#f1c40f" /> <span>Certification Exams</span>
                                </div>
                                <div onClick={() => navigate('/interview')} style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', cursor: 'pointer', padding: '0.4rem' }} className="hover-nav">
                                    <Target size={18} color="#e74c3c" /> <span>AI Mock Interview</span>
                                </div>
                                <div onClick={() => navigate('/resume')} style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', cursor: 'pointer', padding: '0.4rem' }} className="hover-nav">
                                    <FileText size={18} color="#3498db" /> <span>Resume Analyzer</span>
                                </div>
                            </div>
                        </div>

                        <div className="sidebar-card" style={{ background: 'linear-gradient(135deg, rgba(99, 102, 241, 0.1) 0%, rgba(18, 18, 18, 1) 100%)' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.5rem' }}>
                                <Sparkles size={18} color="var(--gfg-brand)" />
                                <h4 style={{ margin: 0, border: 'none', color: 'var(--gfg-brand)' }}>Try Dev2Dev AI</h4>
                            </div>
                            <p style={{ fontSize: '0.85rem', color: 'var(--gfg-text-muted)' }}>Get personalized career guidance and instant code reviews from our Expert AI Teacher.</p>
                        </div>
                    </aside>
                </div>
            </div>

            <style>{`
                .hover-nav:hover { color: var(--gfg-brand); transform: translateX(5px); }
                .dashboard-container { animation: fadeIn 0.4s ease-out; }
                @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
            `}</style>
        </div>
    );
};

export default Dashboard;

import React, { useState, useEffect, useRef } from 'react';
import { Timer, CheckCircle, AlertCircle, ChevronLeft, ChevronRight, SkipForward, Loader2, Brain, CheckSquare, Award, Cpu, Code2, Terminal, Settings, RotateCcw, FileCode, Play, Sparkles, Lock } from 'lucide-react';
import Editor from '@monaco-editor/react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import axios from 'axios';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';
import { generateCertificate, isEligibleForCertificate } from '../utils/certificateGenerator';
import { mockQuestions } from '../data/mockQuestions';
import Loader from '../components/Loader';

const ExamEngine = () => {
    const [searchParams] = useSearchParams();
    const typeQuery = searchParams.get('type');
    const idQuery = searchParams.get('id');

    const [availableExams, setAvailableExams] = useState([]);
    const [loadingExams, setLoadingExams] = useState(true);

    const [examStarted, setExamStarted] = useState(false);
    const [activeExam, setActiveExam] = useState(null);
    const [currentQuestion, setCurrentQuestion] = useState(0);
    const [answers, setAnswers] = useState({});
    const [questions, setQuestions] = useState([]);
    const [submitting, setSubmitting] = useState(false);
    const [result, setResult] = useState(null);
    const [skipsRemaining, setSkipsRemaining] = useState(5);
    const [timeLeft, setTimeLeft] = useState(0);
    const [isRunning, setIsRunning] = useState(false);
    const navigate = useNavigate();
    const editorRef = useRef(null);
    const [editorLoaded, setEditorLoaded] = useState(false);
    const [editorError, setEditorError] = useState(false);
    const [maxUnlockedIndex, setMaxUnlockedIndex] = useState(0);
    const [isFullscreen, setIsFullscreen] = useState(false);

    useEffect(() => {
        const handleFullscreenChange = () => {
            setIsFullscreen(!!document.fullscreenElement);
        };
        document.addEventListener('fullscreenchange', handleFullscreenChange);
        return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
    }, []);

    useEffect(() => {
        const timer = setTimeout(() => {
            if (!editorLoaded) {
                setEditorError(true);
            }
        }, 5000);

        // Strict Anti-Cheat Event Interception at Document Level
        const preventCheat = (e) => {
            e.preventDefault();
            e.stopPropagation();
        };

        const preventShortcuts = (e) => {
            if ((e.ctrlKey || e.metaKey) && ['c', 'v', 'x'].includes(e.key.toLowerCase())) {
                e.preventDefault();
                e.stopPropagation();
            }
        };

        // Capture phase listeners to intercept events before Monaco editor handles them
        document.addEventListener('copy', preventCheat, { capture: true });
        document.addEventListener('cut', preventCheat, { capture: true });
        document.addEventListener('paste', preventCheat, { capture: true });
        document.addEventListener('contextmenu', preventCheat, { capture: true });
        document.addEventListener('keydown', preventShortcuts, { capture: true });

        // Global styles to force no selection while assessment is active
        const style = document.createElement('style');
        style.innerHTML = `
            *:not(.monaco-editor):not(.monaco-editor *) {
                -webkit-user-select: none !important;
                -ms-user-select: none !important;
                user-select: none !important;
            }
        `;
        document.head.appendChild(style);

        return () => {
            clearTimeout(timer);
            document.removeEventListener('copy', preventCheat, { capture: true });
            document.removeEventListener('cut', preventCheat, { capture: true });
            document.removeEventListener('paste', preventCheat, { capture: true });
            document.removeEventListener('contextmenu', preventCheat, { capture: true });
            document.removeEventListener('keydown', preventShortcuts, { capture: true });
            if (document.head.contains(style)) {
                document.head.removeChild(style);
            }
        };
    }, [editorLoaded]);


    useEffect(() => {
        if (typeQuery === 'mock' && idQuery && mockQuestions[idQuery]) {
            // Auto-start the mock if valid mock ID is passed
            const questions = mockQuestions[idQuery].map((q, idx) => ({
                id: q.id,
                type: 'coding',
                questionText: q.title + '\n\n' + q.description,
                starterCode: q.starterCode,
                difficulty: 'Medium'
            }));

            const mockExamObj = {
                title: `SDE Mock Assessment ${idQuery}`,
                durationMinutes: 60,
                questions: questions,
                isMock: true
            };

            startExam(mockExamObj);
            setLoadingExams(false);
            return;
        }

        const fetchExams = async () => {
            try {
                const res = await axios.get(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/users/exams`, {
                    headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
                });
                setAvailableExams(res.data);
            } catch (err) {
                console.error("Error fetching exams:", err);
            } finally {
                setLoadingExams(false);
            }
        };
        fetchExams();
    }, [typeQuery, idQuery]);

    const startExam = (examObj) => {
        setActiveExam(examObj);
        setQuestions(examObj.questions || []);
        setCurrentQuestion(0);
        setAnswers({});
        setSkipsRemaining(5);
        setMaxUnlockedIndex(0);
        setExamStarted(true);
        setResult(null);
        setTimeLeft((examObj.durationMinutes || 30) * 60);
        setIsRunning(true);

        try {
            document.documentElement.requestFullscreen().catch(err => {
                console.log(`Error attempting to enable fullscreen mode: ${err.message}`);
            });
        } catch (e) {
            console.error("Fullscreen API not supported.", e);
        }
    };

    useEffect(() => {
        let timer;
        if (isRunning && timeLeft > 0) {
            timer = setInterval(() => {
                setTimeLeft(prev => prev - 1);
            }, 1000);
        } else if (timeLeft === 0 && isRunning) {
            handleSubmitExam();
        }
        return () => clearInterval(timer);
    }, [isRunning, timeLeft]);

    const formatTime = (seconds) => {
        const h = Math.floor(seconds / 3600);
        const m = Math.floor((seconds % 3600) / 60);
        const s = seconds % 60;
        return `${h > 0 ? h + ':' : ''}${m < 10 ? '0' + m : m}:${s < 10 ? '0' + s : s}`;
    };


    const handleAnswerChange = (val) => {
        setAnswers(prev => ({
            ...prev,
            [currentQuestion]: val
        }));
    };

    const handleKeyDown = (e) => {
        // Monaco handles Tab automatically
    };

    const generatePDF = (reportData) => {
        const doc = new jsPDF();
        const { examName, score, totalMarks, mcqScore, codingScore, detailedAnalysis, dateRun } = reportData;

        // Title
        doc.setFontSize(22);
        doc.setTextColor(33, 150, 243);
        doc.text("Dev2Dev - Exam Report", 105, 20, { align: 'center' });

        // Summary Info
        doc.setFontSize(14);
        doc.setTextColor(0, 0, 0);
        doc.text(`Exam: ${examName}`, 20, 40);
        doc.text(`Score: ${score} / ${totalMarks}`, 20, 50);
        doc.text(`MCQ Correct: ${mcqScore}`, 20, 60);
        doc.text(`Coding Score: ${codingScore}`, 20, 70);
        doc.text(`Date: ${new Date(dateRun).toLocaleDateString()}`, 20, 80);

        // MCQ Results Table
        if (detailedAnalysis?.mcqResults?.length > 0) {
            doc.setFontSize(16);
            doc.text("MCQ Breakdown", 20, 100);
            const mcqTableData = detailedAnalysis.mcqResults.map((m, i) => [
                i + 1,
                m.questionText,
                m.userAnswer || "N/A",
                m.correctAnswer,
                m.isCorrect ? "Correct" : "Wrong"
            ]);
            doc.autoTable({
                startY: 105,
                head: [['#', 'Question', 'Your Answer', 'Correct Answer', 'Result']],
                body: mcqTableData,
                theme: 'striped',
                headStyles: { fillColor: [33, 150, 243] }
            });
        }

        // Coding Results Table
        if (detailedAnalysis?.codingResults?.length > 0) {
            const finalY = doc.lastAutoTable.finalY + 20;
            doc.setFontSize(16);
            doc.text("Coding & Practical Breakdown", 20, finalY);
            const codingTableData = detailedAnalysis.codingResults.map((c, i) => [
                i + 1,
                c.questionText,
                c.userAnswer ? (c.userAnswer.length > 50 ? c.userAnswer.substring(0, 50) + "..." : c.userAnswer) : "Not Attempted",
                c.aiFeedback,
                c.isCorrect ? "Correct" : "Incorrect"
            ]);
            doc.autoTable({
                startY: finalY + 5,
                head: [['#', 'Question', 'Your Solution', 'AI Feedback', 'Status']],
                body: codingTableData,
                theme: 'grid',
                headStyles: { fillColor: [76, 175, 80] }
            });
        }

        doc.save(`${examName}_Report.pdf`);
    };

    const handleSubmitExam = async () => {
        if (!window.confirm("Are you sure you want to submit the exam? This will trigger AI evaluation.")) return;

        setSubmitting(true);

        const token = localStorage.getItem('token');
        if (token) {
            try {
                const response = await axios.post(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/users/submit-exam`, {
                    examName: activeExam.title,
                    answers: answers
                }, {
                    headers: { 'Authorization': `Bearer ${token}` }
                });

                const finalResult = response.data.result;
                setResult(finalResult);
            } catch (e) {
                console.error("Failed to submit exam score to profile", e);
                alert("Evaluation failed. Please check connection.");
            }
        }

        setSubmitting(false);
    };

    const handleDownloadCertificate = () => {
        if (!result) return;

        // Get user name from localStorage or profile
        const userStr = localStorage.getItem('user');
        const userData = userStr ? JSON.parse(userStr) : { name: 'DevElevator' };
        generateCertificate(userData, {
            examName: activeExam.title,
            score: result.score,
            totalMarks: result.totalMarks,
            dateRun: new Date()
        }, 'EXAM');
    };

    if (result) {
        return (
            <div className="container animate-fade-in" style={{ padding: '4rem 1.5rem', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                <div style={{
                    background: result.passed ? 'rgba(129, 140, 248,0.1)' : 'rgba(239,68,68,0.1)',
                    border: result.passed ? '1px solid rgba(129, 140, 248,0.3)' : '1px solid rgba(239,68,68,0.3)',
                    padding: '3rem', borderRadius: '30px', maxWidth: '800px', width: '100%',
                    backdropFilter: 'blur(10px)', textAlign: 'center', marginBottom: '3rem'
                }}>
                    {result.passed ? (
                        <CheckCircle size={64} color="#818cf8" style={{ margin: '0 auto 1.5rem auto' }} />
                    ) : (
                        <AlertCircle size={64} color="#EF4444" style={{ margin: '0 auto 1.5rem auto' }} />
                    )}
                    <h1 style={{ fontSize: '2.5rem', marginBottom: '1rem' }}>
                        {result.passed ? 'Congratulations!' : 'Keep Practicing!'}
                    </h1>
                    <p style={{ fontSize: '1.2rem', color: 'rgba(255,255,255,0.7)', marginBottom: '1rem' }}>
                        You scored <strong>{result.score}</strong> out of <strong>{result.totalMarks}</strong>
                    </p>
                    {result.passed && isEligibleForCertificate(activeExam.title) && (
                        <p style={{ fontSize: '0.95rem', color: '#818cf8', fontWeight: 'bold', marginBottom: '2rem', background: 'rgba(129, 140, 248, 0.1)', display: 'inline-block', padding: '0.5rem 1.5rem', borderRadius: '100px', border: '1px solid rgba(129, 140, 248, 0.2)' }}>
                            <Sparkles size={16} style={{ display: 'inline', marginRight: '8px', marginBottom: '-2px' }} />
                            Official Certificate Ready! Download below or visit your profile.
                        </p>
                    )}

                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '2.5rem' }}>
                        <div style={{ background: 'rgba(255,255,255,0.05)', padding: '1.5rem', borderRadius: '20px' }}>
                            <h3 style={{ fontSize: '0.9rem', color: 'rgba(255,255,255,0.5)', textTransform: 'uppercase' }}>MCQ Correct</h3>
                            <p style={{ fontSize: '1.8rem', fontWeight: '700' }}>{result.mcqScore}</p>
                        </div>
                        <div style={{ background: 'rgba(255,255,255,0.05)', padding: '1.5rem', borderRadius: '20px' }}>
                            <h3 style={{ fontSize: '0.9rem', color: 'rgba(255,255,255,0.5)', textTransform: 'uppercase' }}>Coding Score</h3>
                            <p style={{ fontSize: '1.8rem', fontWeight: '700' }}>{result.codingScore}</p>
                        </div>
                    </div>

                    <div style={{ display: 'flex', gap: '1rem', justifyContent: 'center', flexWrap: 'wrap' }}>
                        {result.passed && isEligibleForCertificate(activeExam.title) && (
                            <button className="btn-primary" onClick={handleDownloadCertificate} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', background: 'linear-gradient(135deg, #6366f1, #a855f7)', border: 'none' }}>
                                <Award size={20} /> Download Certification
                            </button>
                        )}
                        <button className="btn-primary" onClick={() => generatePDF(result)} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                            <SkipForward size={20} /> Download PDF Report
                        </button>
                        <button className="btn-secondary" onClick={() => window.location.reload()}>
                            Retake Exam
                        </button>
                        <button className="btn-secondary" onClick={() => navigate('/profile')}>
                            Detailed Profile
                        </button>
                    </div>
                </div>

                {/* Detailed Analysis Section */}
                <div style={{ textAlign: 'left', width: '100%', maxWidth: '900px' }}>
                    <h2 style={{ marginBottom: '2rem', display: 'flex', alignItems: 'center', gap: '0.75rem', fontSize: '1.8rem' }}>
                        <Brain color="#3B82F6" size={32} /> Detailed AI Analysis
                    </h2>

                    {/* MCQs */}
                    {result.detailedAnalysis?.mcqResults?.length > 0 && (
                        <div style={{ marginBottom: '3rem' }}>
                            <h3 style={{ marginBottom: '1.5rem', color: '#818cf8', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                <CheckSquare size={20} /> MCQ Breakdown
                            </h3>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                                {result.detailedAnalysis.mcqResults.map((item, i) => (
                                    <div key={i} style={{
                                        background: 'rgba(255,255,255,0.03)',
                                        padding: '1.5rem',
                                        borderRadius: '15px',
                                        border: '1px solid rgba(255,255,255,0.05)',
                                        borderLeft: `4px solid ${item.isCorrect ? '#818cf8' : '#EF4444'}`
                                    }}>
                                        <p style={{ fontWeight: '600', marginBottom: '0.75rem', fontSize: '1.05rem' }}>Q{i + 1}: {item.questionText}</p>
                                        <div style={{ fontSize: '0.95rem', display: 'flex', gap: '2rem' }}>
                                            <p>Your Answer: <span style={{ color: item.isCorrect ? '#818cf8' : '#EF4444', fontWeight: 'bold' }}>{item.userAnswer || "N/A"}</span></p>
                                            {!item.isCorrect && <p>Correct: <span style={{ color: '#818cf8', fontWeight: 'bold' }}>{item.correctAnswer}</span></p>}
                                        </div>
                                        <p style={{ fontSize: '0.85rem', color: 'rgba(255,255,255,0.5)', marginTop: '1rem', padding: '0.75rem', background: 'rgba(255,255,255,0.02)', borderRadius: '8px' }}>
                                            <strong>Pro Tip:</strong> {item.explanation}
                                        </p>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}

                    {/* Coding */}
                    {result.detailedAnalysis?.codingResults?.length > 0 && (
                        <div>
                            <h3 style={{ marginBottom: '1.5rem', color: '#3B82F6', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                <Cpu size={20} /> Coding & Practical Feedback
                            </h3>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                                {result.detailedAnalysis.codingResults.map((item, i) => (
                                    <div key={i} style={{
                                        background: 'rgba(255,255,255,0.03)',
                                        padding: '1.5rem',
                                        borderRadius: '15px',
                                        border: '1px solid rgba(255,255,255,0.05)',
                                        borderLeft: `4px solid #3B82F6`
                                    }}>
                                        <p style={{ fontWeight: '600', marginBottom: '1rem', fontSize: '1.05rem' }}>{item.questionText}</p>
                                        <div style={{ background: '#0f172a', padding: '1rem', borderRadius: '10px', fontSize: '0.85rem', color: '#94a3b8', marginBottom: '1.2rem', overflowX: 'auto', border: '1px solid rgba(255,255,255,0.1)' }}>
                                            <pre style={{ margin: 0 }}>{item.userAnswer || "// No solution provided"}</pre>
                                        </div>
                                        <div style={{ display: 'flex', alignItems: 'flex-start', gap: '1rem', background: 'rgba(59,130,246,0.1)', padding: '1.25rem', borderRadius: '12px', border: '1px solid rgba(59,130,246,0.2)' }}>
                                            <Brain size={24} color="#3B82F6" style={{ marginTop: '0.1rem', flexShrink: 0 }} />
                                            <div>
                                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '0.5rem' }}>
                                                    <p style={{ fontWeight: '700', color: '#3B82F6', fontSize: '0.95rem' }}>AI Technical Feedback</p>
                                                    <span style={{
                                                        background: item.isCorrect ? 'rgba(129, 140, 248,0.2)' : 'rgba(239,68,68,0.2)',
                                                        color: item.isCorrect ? '#818cf8' : '#EF4444',
                                                        padding: '0.2rem 0.6rem',
                                                        borderRadius: '6px',
                                                        fontSize: '0.75rem',
                                                        fontWeight: 'bold'
                                                    }}>
                                                        Score: {item.score}/10
                                                    </span>
                                                </div>
                                                <p style={{ fontSize: '0.95rem', color: 'rgba(255,255,255,0.9)', lineHeight: 1.5 }}>{item.aiFeedback}</p>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            </div>
        );
    }

    if (!examStarted) {
        return (
            <div className="container animate-fade-in" style={{ padding: '3rem 1.5rem', maxWidth: '1200px', margin: '0 auto' }}>
                <div style={{ marginBottom: '3.5rem', borderLeft: '4px solid var(--primary)', paddingLeft: '1.5rem' }}>
                    <h1 style={{
                        fontSize: '2.5rem',
                        fontWeight: 850,
                        marginBottom: '0.5rem',
                        color: '#fff',
                        letterSpacing: '-1.5px'
                    }}>
                        Certification Exams
                    </h1>
                    <p style={{ fontSize: '1.1rem', color: 'rgba(255,255,255,0.4)', maxWidth: '600px', lineHeight: 1.6 }}>
                        Test your domain expertise with AI-curated mock assessments and track your progress.
                    </p>
                </div>

                {loadingExams ? (
                    <Loader text="Fetching certification exams..." />
                ) : availableExams.length === 0 ? (
                    <div style={{ padding: '100px', textAlign: 'center', border: '1px dashed rgba(255,255,255,0.05)', borderRadius: '32px', color: 'rgba(255,255,255,0.3)' }}>
                        <Brain size={48} style={{ marginBottom: '1rem', opacity: 0.2 }} />
                        <p>No certification exams are currently available for your profile.</p>
                    </div>
                ) : (
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))', gap: '2rem', width: '100%', maxWidth: '1100px', margin: '0 auto' }}>
                        {availableExams.map(ex => {
                            const isFullLength = ex.type === 'Full-length Mock';
                            const isTopicWise = ex.type === 'Topic-wise';

                            // Define visual themes
                            const themeColor = isFullLength ? 'var(--primary)' : (isTopicWise ? '#818cf8' : '#F59E0B');
                            const themeGradient = isFullLength
                                ? 'linear-gradient(135deg, rgba(99,102,241,0.15) 0%, rgba(99,102,241,0.02) 100%)'
                                : (isTopicWise ? 'linear-gradient(135deg, rgba(129, 140, 248,0.15) 0%, rgba(129, 140, 248,0.02) 100%)'
                                    : 'linear-gradient(135deg, rgba(245,158,11,0.15) 0%, rgba(245,158,11,0.02) 100%)');

                            return (
                                <div key={ex._id} className="card glass-panel group"
                                    style={{
                                        display: 'flex', flexDirection: 'column', textAlign: 'left',
                                        padding: '2rem',
                                        border: `1px solid rgba(255,255,255,0.08)`,
                                        background: 'rgba(20,20,30,0.6)',
                                        transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
                                        boxShadow: '0 10px 30px -10px rgba(0,0,0,0.5)',
                                        borderRadius: '24px',
                                        position: 'relative',
                                        overflow: 'hidden'
                                    }}
                                    onMouseEnter={(e) => {
                                        e.currentTarget.style.transform = 'translateY(-6px)';
                                        e.currentTarget.style.borderColor = themeColor;
                                        e.currentTarget.style.boxShadow = `0 20px 40px -10px ${themeColor}40`;
                                    }}
                                    onMouseLeave={(e) => {
                                        e.currentTarget.style.transform = 'none';
                                        e.currentTarget.style.borderColor = 'rgba(255,255,255,0.08)';
                                        e.currentTarget.style.boxShadow = '0 10px 30px -10px rgba(0,0,0,0.5)';
                                    }}
                                >
                                    {/* Glow Background */}
                                    <div style={{
                                        position: 'absolute', top: 0, left: 0, right: 0, bottom: 0,
                                        background: themeGradient,
                                        zIndex: 0, pointerEvents: 'none'
                                    }} />

                                    {/* Top Badge */}
                                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.2rem', zIndex: 1 }}>
                                        <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
                                            {isFullLength && <span style={{ background: themeColor, color: '#fff', fontSize: '0.7rem', fontWeight: 'bold', padding: '0.3rem 0.8rem', borderRadius: '12px', textTransform: 'uppercase', letterSpacing: '0.5px', boxShadow: `0 0 10px ${themeColor}80` }}><Award size={12} style={{ display: 'inline', marginRight: '4px', marginBottom: '-2px' }} /> PREMIUM MOCK</span>}
                                            {!isFullLength && <span style={{ background: 'rgba(255,255,255,0.1)', color: 'var(--text)', fontSize: '0.7rem', fontWeight: 'bold', padding: '0.3rem 0.8rem', borderRadius: '12px', textTransform: 'uppercase', letterSpacing: '0.5px' }}>{ex.type}</span>}
                                        </div>
                                        {ex.domainId && (
                                            <span style={{ fontSize: '0.8rem', color: themeColor, display: 'flex', alignItems: 'center', gap: '0.4rem', fontWeight: '600' }}>
                                                <Cpu size={14} /> {ex.domainId.name}
                                            </span>
                                        )}
                                    </div>

                                    {/* Title */}
                                    <h3 style={{ margin: '0 0 0.8rem 0', fontSize: '1.5rem', fontWeight: '800', color: 'var(--text)', zIndex: 1, lineHeight: '1.3', letterSpacing: '-0.5px' }}>
                                        {ex.title}
                                    </h3>

                                    {/* Description placeholder */}
                                    <p style={{ color: 'var(--text-muted)', fontSize: '0.95rem', marginBottom: '1.5rem', zIndex: 1, lineHeight: '1.6', flexGrow: 1 }}>
                                        {isFullLength
                                            ? "Comprehensive simulation to test your complete readiness. Includes theoretical and practical coding concepts to evaluate your domain knowledge."
                                            : "Targeted practice session designed to strengthen your foundational concepts and problem-solving speed."}
                                    </p>

                                    {/* Meta details */}
                                    <div style={{ display: 'flex', gap: '1rem', marginBottom: '1.5rem', zIndex: 1, padding: '1rem 0', borderTop: '1px solid rgba(255,255,255,0.05)', borderBottom: '1px solid rgba(255,255,255,0.05)' }}>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.6rem', flex: 1 }}>
                                            <div style={{ padding: '0.5rem', background: 'rgba(255,255,255,0.05)', borderRadius: '8px', color: themeColor }}><Timer size={16} /></div>
                                            <div><div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600, textTransform: 'uppercase' }}>Duration</div><div style={{ color: 'var(--text)', fontWeight: 700 }}>{ex.durationMinutes} Mins</div></div>
                                        </div>
                                        <div style={{ width: '1px', background: 'rgba(255,255,255,0.05)' }}></div>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.6rem', flex: 1, paddingLeft: '0.5rem' }}>
                                            <div style={{ padding: '0.5rem', background: 'rgba(255,255,255,0.05)', borderRadius: '8px', color: themeColor }}><CheckSquare size={16} /></div>
                                            <div><div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600, textTransform: 'uppercase' }}>Questions</div><div style={{ color: 'var(--text)', fontWeight: 700 }}>{ex.questions?.length || 0} Qs</div></div>
                                        </div>
                                    </div>

                                    {/* Action button */}
                                    <button
                                        className="btn"
                                        onClick={() => startExam(ex)}
                                        style={{
                                            width: '100%',
                                            zIndex: 1,
                                            background: (!ex.questions || ex.questions.length === 0) ? 'rgba(255,255,255,0.05)' : themeColor,
                                            color: (!ex.questions || ex.questions.length === 0) ? 'var(--text-muted)' : '#fff',
                                            border: 'none',
                                            padding: '1rem',
                                            fontWeight: '700',
                                            fontSize: '1rem',
                                            transition: 'all 0.2s ease',
                                            borderRadius: '12px',
                                            boxShadow: (!ex.questions || ex.questions.length === 0) ? 'none' : `0 4px 15px -5px ${themeColor}80`
                                        }}
                                        onMouseEnter={(e) => {
                                            if (ex.questions && ex.questions.length > 0) {
                                                e.currentTarget.style.filter = 'brightness(1.1)';
                                                e.currentTarget.style.transform = 'translateY(-2px)';
                                            }
                                        }}
                                        onMouseLeave={(e) => {
                                            if (ex.questions && ex.questions.length > 0) {
                                                e.currentTarget.style.filter = 'none';
                                                e.currentTarget.style.transform = 'none';
                                            }
                                        }}
                                        disabled={!ex.questions || ex.questions.length === 0}
                                    >
                                        {(!ex.questions || ex.questions.length === 0) ? 'No Questions Yet' : 'Start Assessment'}
                                    </button>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        );
    }

    const q = questions[currentQuestion];

    return (
        <div
            className="container animate-fade-in"
            style={{
                padding: isFullscreen ? '2rem 5vw' : '2rem 1.5rem',
                maxWidth: isFullscreen ? '100vw' : '1200px',
                margin: '0 auto',
                display: 'flex',
                gap: isFullscreen ? '3rem' : '2rem',
                alignItems: 'flex-start',
                transition: 'all 0.4s ease-in-out',
                height: isFullscreen ? '100vh' : 'auto',
                overflow: isFullscreen ? 'hidden' : 'visible',
                userSelect: 'none',
                WebkitUserSelect: 'none',
                msUserSelect: 'none',
                MozUserSelect: 'none'
            }}
            onCopy={(e) => e.preventDefault()}
            onCut={(e) => e.preventDefault()}
            onPaste={(e) => e.preventDefault()}
        >

            {/* Sidebar for Navigation */}
            <div className="card glass-panel" style={{
                width: isFullscreen ? '350px' : '300px',
                flexShrink: 0,
                height: isFullscreen ? 'calc(100vh - 4rem)' : 'calc(100vh - 120px)',
                overflowY: 'auto',
                position: isFullscreen ? 'static' : 'sticky',
                top: isFullscreen ? '0' : '80px',
                padding: '1.5rem',
                transition: 'width 0.3s ease, height 0.3s ease'
            }}>
                <h3 style={{ marginBottom: '1rem', borderBottom: '1px solid var(--border)', paddingBottom: '0.5rem' }}>Questions Navigation</h3>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: '0.5rem' }}>
                    {questions.map((_, idx) => {
                        const isAnswered = answers[idx] !== undefined && answers[idx] !== '';
                        const isCurrent = currentQuestion === idx;

                        const handleSidebarClick = () => {
                            if (idx <= maxUnlockedIndex) {
                                setCurrentQuestion(idx);
                            } else {
                                alert("Please answer or skip the current question to unlock this one.");
                            }
                        };

                        return (
                            <button
                                key={idx}
                                onClick={handleSidebarClick}
                                style={{
                                    padding: '0.5rem 0',
                                    borderRadius: 'var(--radius-sm)',
                                    border: isCurrent ? '2px solid var(--primary)' : '1px solid var(--border)',
                                    background: idx > maxUnlockedIndex ? 'rgba(255,255,255,0.02)' : (isAnswered ? 'var(--primary-light)' : 'var(--bg-secondary)'),
                                    color: idx > maxUnlockedIndex ? 'rgba(255,255,255,0.1)' : (isAnswered ? 'var(--text)' : 'var(--text-secondary)'),
                                    cursor: idx > maxUnlockedIndex ? 'not-allowed' : 'pointer',
                                    fontWeight: isCurrent ? 'bold' : 'normal',
                                    transition: 'all 0.2s',
                                    display: 'flex',
                                    flexDirection: 'column',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    position: 'relative'
                                }}
                            >
                                {idx + 1}
                                {idx > maxUnlockedIndex && <Lock size={10} style={{ position: 'absolute', top: '2px', right: '2px', opacity: 0.5 }} />}
                            </button>
                        );
                    })}
                </div>
                <div style={{ marginTop: '2rem' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.5rem', fontSize: '0.85rem' }}><div style={{ width: 12, height: 12, background: 'var(--primary-light)', borderRadius: '2px' }}></div> Answered</div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.5rem', fontSize: '0.85rem' }}><div style={{ width: 12, height: 12, background: 'var(--bg-secondary)', border: '1px solid var(--border)', borderRadius: '2px' }}></div> Unanswered</div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.85rem' }}><div style={{ width: 12, height: 12, border: '2px solid var(--primary)', borderRadius: '2px' }}></div> Current</div>
                </div>
            </div>

            {/* Main Exam Area */}
            <div style={{ flex: 1, display: 'flex', flexDirection: 'column', minWidth: 0, height: isFullscreen ? 'calc(100vh - 4rem)' : 'auto', transition: 'height 0.3s ease' }}>
                <div className="flex-between" style={{ marginBottom: '1.5rem', padding: '1rem', background: 'var(--bg-secondary)', borderRadius: 'var(--radius-md)' }}>
                    <div className="flex-center" style={{ gap: '0.5rem' }}>
                        <AlertCircle size={20} color="var(--warning)" />
                        <span style={{ fontWeight: 'bold', fontSize: isFullscreen ? '1.1rem' : '1rem' }}>Question {currentQuestion + 1} of {questions.length}</span>
                        <span className="badge" style={{ marginLeft: '1rem', background: 'var(--primary-light)', padding: '0.2rem 0.6rem', borderRadius: '4px', fontSize: '0.8rem' }}>
                            {q?.difficulty || 'Medium'}
                        </span>
                    </div>
                    <div className="flex-center" style={{ gap: '0.5rem', color: 'var(--danger)', fontWeight: 'bold' }}>
                        <Brain size={18} color="#A5B4FC" />
                        <span style={{ color: '#A5B4FC', marginRight: '1rem' }}>Skips: {skipsRemaining}</span>
                        <Timer size={20} />
                        <span>{formatTime(timeLeft)}</span>
                    </div>
                </div>

                <div className="card glass-panel" style={{
                    marginBottom: '2rem',
                    flex: 1,
                    display: 'flex',
                    flexDirection: 'column',
                    minHeight: '650px',
                    background: 'rgba(15, 15, 25, 0.7)',
                    border: '1px solid rgba(255,255,255,0.05)',
                    boxShadow: '0 20px 50px rgba(0,0,0,0.3)'
                }}>
                    <div style={{ padding: '1.5rem', borderBottom: '1px solid rgba(255,255,255,0.05)', background: 'rgba(255,255,255,0.02)' }}>
                        <h2 style={{ fontSize: '1.25rem', lineHeight: 1.6, color: '#fff', margin: 0 }}>
                            {q?.questionText || q?.q || 'No question text provided'}
                        </h2>
                    </div>

                    {(() => {
                        const isTerminalMode =
                            activeExam?.title?.toLowerCase().includes('cyber security') ||
                            activeExam?.title?.toLowerCase().includes('linux') ||
                            q?.questionText?.toLowerCase().includes('linux') ||
                            q?.questionText?.toLowerCase().includes('bash') ||
                            q?.questionText?.toLowerCase().includes('terminal');

                        if ((q?.type?.toLowerCase() === 'mcq' && q?.options && q.options.length > 0) || (q?.options && q?.options.length > 0 && q?.type !== 'coding')) {
                            return (
                                <div style={{ padding: '2rem', display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                                    {(q?.options || []).map((opt, i) => (
                                        <label key={i} style={{
                                            display: 'flex', alignItems: 'center', gap: '1rem',
                                            padding: '1.2rem', borderRadius: '16px',
                                            background: answers[currentQuestion] === opt ? 'rgba(99, 102, 241, 0.15)' : 'rgba(255,255,255,0.03)',
                                            border: `1px solid ${answers[currentQuestion] === opt ? 'var(--primary)' : 'rgba(255,255,255,0.08)'}`,
                                            cursor: 'pointer', transition: 'all 0.2s ease'
                                        }}>
                                            <input
                                                type="radio"
                                                name={`q-${currentQuestion}`}
                                                checked={answers[currentQuestion] === opt}
                                                onChange={() => handleAnswerChange(opt)}
                                                style={{ accentColor: 'var(--primary)', width: '18px', height: '18px' }}
                                            />
                                            <span style={{ fontSize: '1.05rem', color: answers[currentQuestion] === opt ? '#fff' : 'rgba(255,255,255,0.8)' }}>{opt}</span>
                                        </label>
                                    ))}
                                </div>
                            );
                        }

                        return (
                            <div style={{
                                display: 'flex',
                                flexDirection: 'column',
                                flex: 1,
                                minHeight: '500px',
                                border: `1px solid ${isTerminalMode ? '#333' : 'rgba(255,255,255,0.1)'}`,
                                borderRadius: '12px',
                                overflow: 'visible',
                                margin: '1.5rem',
                                background: isTerminalMode ? '#000' : '#1e1e1e',
                                boxShadow: '0 10px 30px rgba(0,0,0,0.5)'
                            }}>
                                {/* VS Code Style / Terminal Header */}
                                <div style={{
                                    display: 'flex',
                                    justifyContent: 'space-between',
                                    alignItems: 'center',
                                    background: isTerminalMode ? '#1e1e1e' : '#252526',
                                    padding: '0 1rem',
                                    height: '35px',
                                    borderBottom: '1px solid rgba(255,255,255,0.05)'
                                }}>
                                    <div style={{ display: 'flex', alignItems: 'center', height: '100%' }}>
                                        <div style={{
                                            background: isTerminalMode ? '#000' : '#1e1e1e',
                                            padding: '0 1rem',
                                            height: '100%',
                                            display: 'flex',
                                            alignItems: 'center',
                                            gap: '8px',
                                            borderTop: `1px solid ${isTerminalMode ? '#4ec9b0' : '#007acc'}`,
                                            fontSize: '0.8rem',
                                            color: '#cccccc'
                                        }}>
                                            {isTerminalMode ? <Terminal size={14} color="#4ec9b0" /> : <FileCode size={14} color="#519aba" />}
                                            <span>{isTerminalMode ? 'root@terminal:~' : 'solution.js'}</span>
                                        </div>
                                    </div>
                                    <div style={{ display: 'flex', gap: '15px', color: 'rgba(255,255,255,0.4)' }}>
                                        <RotateCcw size={14} style={{ cursor: 'pointer' }} onClick={() => handleAnswerChange(q?.starterCode || '')} />
                                        <Settings size={14} style={{ cursor: 'pointer' }} />
                                    </div>
                                </div>

                                {/* Editor Body / Terminal Prompt */}
                                <div style={{ flex: 1, minHeight: '400px', position: 'relative', overflow: 'hidden' }}>
                                    {isTerminalMode && (
                                        <div style={{
                                            position: 'absolute',
                                            top: 0,
                                            left: 0,
                                            bottom: 0,
                                            width: '45px',
                                            padding: '1.5rem 0.5rem 0 1.5rem',
                                            color: '#4ec9b0',
                                            fontFamily: 'monospace',
                                            fontSize: '1rem',
                                            lineHeight: '1.7',
                                            background: '#000',
                                            zIndex: 10,
                                            borderRight: '1px solid rgba(255,255,255,0.05)'
                                        }}>
                                            #
                                        </div>
                                    )}
                                    {editorError ? (
                                        <div style={{ padding: '2rem', background: '#1e1e1e', border: '1px solid rgba(255,255,255,0.05)', borderRadius: '12px' }}>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', color: '#4ec9b0', marginBottom: '1rem', fontWeight: 'bold' }}>
                                                <Terminal size={18} />
                                                <span>Classic Editor Active</span>
                                            </div>
                                            <p style={{ color: 'rgba(255,255,255,0.4)', fontSize: '0.85rem', marginBottom: '1.5rem', lineHeight: '1.5' }}>
                                                Your current connection is optimized for our high-performance editor.
                                                You are now using the <span style={{ color: '#4ec9b0' }}>Classic Mode</span> for maximum reliability.
                                            </p>
                                            <textarea
                                                style={{
                                                    width: '100%',
                                                    height: '350px',
                                                    background: '#0a0a0a',
                                                    color: '#d4d4d4',
                                                    border: '1px solid rgba(255,255,255,0.1)',
                                                    borderRadius: '8px',
                                                    padding: '1.5rem',
                                                    fontFamily: '"Fira Code", "Consolas", monospace',
                                                    fontSize: '0.95rem',
                                                    outline: 'none',
                                                    resize: 'none',
                                                    lineHeight: '1.6',
                                                    boxShadow: 'inset 0 2px 10px rgba(0,0,0,0.5)'
                                                }}
                                                value={answers[currentQuestion] || ''}
                                                onChange={(e) => handleAnswerChange(e.target.value)}
                                                placeholder="// Enter your solution here..."
                                            />
                                        </div>
                                    ) : (
                                        <Editor
                                            loading={<div style={{ color: '#4ec9b0', padding: '2rem', fontFamily: 'monospace', background: '#1e1e1e', height: '400px' }}>⚡ Connecting to Cloud Editor Engine...</div>}
                                            height="400px"
                                            language="javascript"
                                            theme="vs-dark"
                                            value={answers[currentQuestion] !== undefined ? answers[currentQuestion] : (q?.starterCode || '// Start typing your solution here...\n')}
                                            onChange={handleAnswerChange}
                                            onMount={(editor, monaco) => {
                                                console.log("Monaco Mounted");
                                                setEditorLoaded(true);
                                                editorRef.current = editor;

                                                // Intercept copy/paste specifically within Monaco Editor
                                                editor.onKeyDown((e) => {
                                                    if (e.ctrlKey || e.metaKey) {
                                                        // KeyCode 33 = C, 52 = V, 53 = X
                                                        if (e.keyCode === monaco.KeyCode.KeyC || e.keyCode === monaco.KeyCode.KeyV || e.keyCode === monaco.KeyCode.KeyX) {
                                                            e.preventDefault();
                                                            e.stopPropagation();
                                                        }
                                                    }
                                                });
                                            }}
                                            options={{
                                                fontSize: 14,
                                                fontFamily: '"Fira Code", "Consolas", monospace',
                                                minimap: { enabled: false },
                                                scrollBeyondLastLine: false,
                                                lineNumbers: isTerminalMode ? 'off' : 'on',
                                                automaticLayout: true,
                                                tabSize: 4,
                                                padding: { top: 16, left: isTerminalMode ? 35 : 0 },
                                                readOnly: false,
                                                renderLineHighlight: isTerminalMode ? 'none' : 'all',
                                                contextmenu: false, // Disable right-click inside the editor
                                                scrollbar: {
                                                    vertical: 'visible',
                                                    horizontal: 'visible'
                                                }
                                            }}
                                        />
                                    )}
                                </div>

                                {/* Footer Output Area */}
                                <div style={{
                                    background: isTerminalMode ? '#1e1e1e' : '#1e1e1e',
                                    borderTop: '1px solid rgba(255,255,255,0.1)',
                                    padding: '1rem'
                                }}>
                                    {/* Run Code functionality removed for Exam Mode */}
                                </div>
                            </div>
                        );
                    })()}
                </div>

                <div className="flex-between">
                    <button
                        className="btn btn-outline"
                        disabled={currentQuestion === 0}
                        onClick={() => setCurrentQuestion(prev => prev - 1)}
                    >
                        <ChevronLeft size={18} style={{ marginRight: '0.5rem' }} /> Previous
                    </button>

                    <div style={{ display: 'flex', gap: '1rem' }}>
                        {currentQuestion < questions.length - 1 && (
                            <button
                                className="btn btn-outline"
                                onClick={() => {
                                    if (skipsRemaining > 0) {
                                        setSkipsRemaining(prev => prev - 1);
                                        setMaxUnlockedIndex(prev => Math.max(prev, currentQuestion + 1));
                                        setCurrentQuestion(prev => prev + 1);
                                    } else {
                                        alert("No more skips available! You must answer this question.");
                                    }
                                }}
                                style={{ borderColor: skipsRemaining === 0 ? 'rgba(239,68,68,0.3)' : 'var(--border)' }}
                            >
                                Skip <SkipForward size={18} style={{ marginLeft: '0.5rem' }} />
                                <span style={{ fontSize: '0.7rem', opacity: 0.6, marginLeft: '5px' }}>({skipsRemaining})</span>
                            </button>
                        )}

                        {currentQuestion < questions.length - 1 ? (
                            <button
                                className="btn btn-primary"
                                onClick={() => {
                                    if (answers[currentQuestion]) {
                                        setMaxUnlockedIndex(prev => Math.max(prev, currentQuestion + 1));
                                        setCurrentQuestion(prev => prev + 1);
                                    } else {
                                        alert("Please answer this question or use 'Skip' to proceed.");
                                    }
                                }}
                                style={{
                                    opacity: answers[currentQuestion] ? 1 : 0.6,
                                    cursor: answers[currentQuestion] ? 'pointer' : 'not-allowed'
                                }}
                            >
                                Next <ChevronRight size={18} style={{ marginLeft: '0.5rem' }} />
                            </button>
                        ) : (
                            <button
                                className="btn btn-primary"
                                disabled={submitting || !answers[currentQuestion]}
                                style={{ background: answers[currentQuestion] ? 'var(--success)' : 'rgba(255,255,255,0.1)', border: 'none' }}
                                onClick={handleSubmitExam}
                            >
                                {submitting ? <Loader2 className="animate-spin" size={20} /> : <CheckCircle size={20} style={{ marginRight: '0.5rem' }} />}
                                {submitting ? 'Evaluating...' : 'Submit Exam'}
                            </button>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default ExamEngine;

import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { Mail, Loader2, ArrowRight, ShieldCheck, Zap } from 'lucide-react';
import Loader from '../components/Loader';
import './Auth.css';

const ForgotPassword = () => {
    const [email, setEmail] = useState('');
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');
    const [error, setError] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');
        setMessage('');

        try {
            const res = await fetch(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/auth/forgot-password`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ email })
            });
            const data = await res.json();
            if (res.ok) {
                setMessage(data.devMode ? 'Dev Mode: Access link logged to Server Terminal!' : 'Recovery link dispatched to your inbox.');
            } else {
                setError(data.message || 'Transmission error');
            }
        } catch (err) {
            setError('System fault. Please check back later.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="auth-page">
            <div className="auth-side-visual">
                <div className="auth-visual-pill">
                    <ShieldCheck size={14} />
                    <span>Secure Your Legacy</span>
                </div>
                <h1 className="auth-visual-title">
                    Reclaim Your <br />
                    <span className="highlight">Identity.</span>
                </h1>
                <p className="auth-visual-subtitle">
                    We've got your back. Securely recover your Vault ID and get back to building the future.
                </p>

                <div className="auth-feature-grid">
                    <div className="auth-feature-card">
                        <Lock size={24} color="#818cf8" />
                        <h4>Encrypted Recovery</h4>
                        <p>Military-grade encryption protects your authorization protocols.</p>
                    </div>
                    <div className="auth-feature-card">
                        <Sparkles size={24} color="var(--auth-accent)" />
                        <h4>Instant Access</h4>
                        <p>Resume your roadmap exactly where you left off.</p>
                    </div>
                </div>
            </div>

            <div className="auth-side-form">
                <div className="auth-form-card">
                    <header className="auth-header">
                        <img src="/logo.png" alt="Dev2Dev" className="auth-logo" />
                        <h2>Recover Access</h2>
                        <p>Enter your registered Vault ID</p>
                    </header>

                    {message && (
                        <div style={{ background: 'rgba(129, 140, 248, 0.1)', border: '1px solid rgba(129, 140, 248, 0.2)', color: '#818cf8', padding: '1rem', borderRadius: '18px', marginBottom: '2.5rem', textAlign: 'center', fontWeight: 600 }}>
                            {message}
                        </div>
                    )}

                    {error && <div className="auth-error-badge">{error}</div>}

                    <form onSubmit={handleSubmit}>
                        <div className="auth-field">
                            <label className="auth-label">Registered Email</label>
                            <div className="auth-input-wrapper">
                                <Mail size={20} color="rgba(255,255,255,0.2)" style={{ marginRight: '1rem' }} />
                                <input
                                    type="email"
                                    className="auth-input"
                                    placeholder="nexus@dev.com"
                                    value={email}
                                    onChange={(e) => setEmail(e.target.value)}
                                    required
                                />
                            </div>
                        </div>

                        <button type="submit" className="auth-btn-primary" disabled={loading}>
                            {loading ? <Loader text="Sending recovery link..." /> : <>Send Key Upgrade <ArrowRight size={20} /></>}
                        </button>
                    </form>

                    <footer className="auth-footer-text" style={{ marginTop: '3.5rem' }}>
                        <Link to="/login" style={{ display: 'inline-flex', alignItems: 'center', gap: '0.6rem', color: 'var(--auth-accent)', textDecoration: 'none', fontWeight: 800 }}>
                            <ArrowLeft size={18} /> Return to Home
                        </Link>
                    </footer>
                </div>
            </div>
        </div>
    );
};

export default ForgotPassword;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { Target, MonitorPlay, ChevronRight, Activity, Users, FileText, Code2, Briefcase, Loader2, Lock, Sparkles, Trophy, Star, Search, LogIn, Clock, Zap, ArrowRight } from 'lucide-react';
import Loader from '../components/Loader';

const InterviewPrep = () => {
    const navigate = useNavigate();
    const [loading, setLoading] = useState(true);
    const [stats, setStats] = useState({});
    const [showModal, setShowModal] = useState(false);
    const [selectedMock, setSelectedMock] = useState(null);
    const [isPro, setIsPro] = useState(false);

    useEffect(() => {
        const fetchData = async () => {
            try {
                const token = localStorage.getItem('token');
                const res = await axios.get(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/users/mock-stats`, {
                    headers: { Authorization: `Bearer ${token}` }
                });
                setStats(res.data || {});
            } catch (err) {
                console.error("Failed to fetch mock stats:", err);
            } finally {
                const userString = localStorage.getItem('user');
                if (userString) {
                    try {
                        const user = JSON.parse(userString);
                        setIsPro(user.hasProAccess || user.isPro === true);
                    } catch (e) { }
                }
                setLoading(false);
            }
        };
        fetchData();
    }, []);

    const freeMocks = [
        {
            type: 'Online Assessment',
            title: 'Digital Qualifier',
            desc: 'Simulate the first hurdle. 2 questions, 60 minutes. Randomized for every attempt.',
            path: 'Online Assessment',
            color: 'hsl(250, 100%, 70%)'
        },
        {
            type: 'Phone Interview',
            title: 'Technical Screen',
            desc: 'Deep dive into 1 core problem. Focus on communication and clean logic.',
            path: 'Phone Interview',
            color: 'hsl(180, 100%, 45%)'
        },
        {
            type: 'Onsite Interview',
            title: 'Onsite Loop',
            desc: 'The final boss. 3 questions back-to-back. Tests endurance and edge cases.',
            path: 'Onsite Interview',
            color: 'hsl(320, 100%, 65%)'
        }
    ];

    const premiumCompanies = [
        { name: 'Google', sets: 13, logo: 'https://upload.wikimedia.org/wikipedia/commons/2/2f/Google_2015_logo.svg' },
        { name: 'Meta', sets: 12, logo: 'https://upload.wikimedia.org/wikipedia/commons/7/7b/Meta_Platforms_Inc._logo.svg' },
        { name: 'Amazon', sets: 13, logo: 'https://upload.wikimedia.org/wikipedia/commons/a/a9/Amazon_logo.svg' },
        { name: 'Microsoft', sets: 8, logo: 'https://upload.wikimedia.org/wikipedia/commons/4/44/Microsoft_logo.svg' },
        { name: 'Apple', sets: 7, logo: 'https://upload.wikimedia.org/wikipedia/commons/f/fa/Apple_logo_black.svg' },
        { name: 'Netflix', sets: 5, logo: 'https://upload.wikimedia.org/wikipedia/commons/0/08/Netflix_2015_logo.svg' },
        { name: 'Uber', sets: 4, logo: 'https://upload.wikimedia.org/wikipedia/commons/5/58/Uber_logo_2018.svg' },
        { name: 'Airbnb', sets: 3, logo: 'https://upload.wikimedia.org/wikipedia/commons/6/69/Airbnb_Logo_Belo.svg' }
    ];

    const getStat = (id) => stats[id] || { attempts: 0, successRate: "0%" };

    const handleStartMock = (mock) => {
        setSelectedMock(mock);
        setShowModal(true);
    };

    const confirmStart = () => {
        if (selectedMock) {
            navigate(`/mock-assessment?type=${encodeURIComponent(selectedMock.path)}`);
            setShowModal(false);
        }
    };

    const handleCheckout = async () => {
        try {
            const token = localStorage.getItem('token');
            const { data: order } = await axios.post(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/payment/create-order`,
                { type: 'pro', amount: 49 }, // e.g. 49 INR for Pro
                { headers: { Authorization: `Bearer ${token}` } }
            );

            const options = {
                key: import.meta.env.VITE_RAZORPAY_KEY_ID,
                amount: order.amount,
                currency: order.currency,
                name: "Dev2Dev",
                description: "Pro Interview Prep (1 Year Access)",
                order_id: order.id,
                handler: async function (response) {
                    try {
                        const verifyRes = await axios.post(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/payment/verify-payment`, {
                            razorpay_order_id: response.razorpay_order_id,
                            razorpay_payment_id: response.razorpay_payment_id,
                            razorpay_signature: response.razorpay_signature,
                            type: 'pro'
                        }, { headers: { Authorization: `Bearer ${token}` } });

                        if (verifyRes.data.isPro) {
                            setIsPro(true);
                            // Update local storage
                            const userString = localStorage.getItem('user');
                            if (userString) {
                                const user = JSON.parse(userString);
                                user.isPro = true;
                                localStorage.setItem('user', JSON.stringify(user));
                            }
                            alert("Payment Successful! You are now a Pro member.");
                        }
                    } catch (error) {
                        console.error("Payment verification failed", error);
                        alert("Payment verification failed.");
                    }
                },
                theme: {
                    color: "#6366f1"
                }
            };
            const rzp1 = new window.Razorpay(options);
            rzp1.on('payment.failed', function (response) {
                alert("Payment Failed: " + response.error.description);
            });
            rzp1.open();
        } catch (error) {
            console.error("Error initiating checkout:", error);
            alert("Could not initiate checkout. Please try again.");
        }
    };

    if (loading) {
