                                        <span>{s.attempts} Global Attempts</span>
                                    </div>
                                    <div className="card-stat">
                                        <Activity size={14} />
                                        <span>{s.successRate} Pass Rate</span>
                                    </div>
                                </div>

                                <button className="start-btn-v2" onClick={() => handleStartMock(mock)}>
                                    <span>Practice Now</span>
                                    <ArrowRight size={16} />
                                </button>
                            </div>
                        );
                    })}
