                {/* Company Grid */}
                <div style={{ marginTop: '6rem' }}>
                    <div className="flex-between" style={{ marginBottom: '3rem' }}>
                        <div>
                            <h2 style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>Company Playloads</h2>
