                                            <div style={{ background: 'rgba(255,255,255,0.03)', padding: '1rem', borderRadius: '8px', border: '1px solid rgba(255,255,255,0.05)' }}>
                                                <p style={{ margin: 0, opacity: 0.6, fontSize: '0.8rem', marginBottom: '0.75rem' }}>Result Analysis:</p>
