import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { Mic, MicOff, Video, VideoOff, Square, FileText, CheckCircle, UploadCloud, User, Briefcase, Loader2, Play, Volume2, ArrowRight, AlertCircle, RefreshCw, Cpu, AlertTriangle, BookOpen, Zap, Lock, Trophy } from 'lucide-react';
import axios from 'axios';
import './MockInterview.css';

const Waveform = ({ active, color }) => (
    <div style={{ display: 'flex', alignItems: 'center', gap: '3px', height: '30px' }}>
        {[1, 2, 3, 4, 5, 2, 4, 1, 3, 5].map((h, i) => (
            <div
                key={i}
                style={{
                    width: '3px',
                    height: active ? `${h * 4}px` : '4px',
                    background: color,
                    borderRadius: '10px',
                    transition: 'height 0.2s ease-in-out',
                    animation: active ? `wave 1s ease-in-out infinite ${i * 0.1}s` : 'none'
                }}
            />
        ))}
    </div>
);

const StatRing = ({ value, label, color, icon: Icon }) => {
    const radius = 40;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (value / 100) * circumference;

    return (
        <div className="stat-ring-container" style={{ textAlign: 'center', padding: '1.5rem', background: 'rgba(255,255,255,0.02)', borderRadius: '24px', border: '1px solid rgba(255,255,255,0.05)', transition: '0.3s' }}>
            <div style={{ position: 'relative', width: '100px', height: '100px', margin: '0 auto 1.5rem' }}>
                <svg width="100" height="100" style={{ transform: 'rotate(-90deg)' }}>
                    <circle cx="50" cy="50" r={radius} fill="transparent" stroke="rgba(255,255,255,0.05)" strokeWidth="8" />
                    <circle
                        cx="50" cy="50" r={radius}
                        fill="transparent"
                        stroke={color}
                        strokeWidth="8"
                        strokeDasharray={circumference}
                        strokeDashoffset={offset}
                        strokeLinecap="round"
                        style={{ transition: 'stroke-dashoffset 2s ease-out' }}
                    />
                </svg>
                <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', flexDirection: 'column' }}>
                    <span style={{ fontSize: '1.25rem', fontWeight: 900, color: '#fff' }}>{value}%</span>
                </div>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem', color: color }}>
                <Icon size={14} />
                <span style={{ fontSize: '0.7rem', fontWeight: 800, textTransform: 'uppercase', letterSpacing: '1px' }}>{label}</span>
            </div>
        </div>
    );
};

const MockInterview = () => {
    // Stage: 'setup', 'interviewing', 'analysing', 'results'
    const [stage, setStage] = useState('setup');
    const [jobProfile, setJobProfile] = useState('');
    const [resumeText, setResumeText] = useState('');
    const [isUploading, setIsUploading] = useState(false);
    const [isCameraOn, setIsCameraOn] = useState(true);
    const [isRecording, setIsRecording] = useState(false);
    const [isAITyping, setIsAITyping] = useState(false);
    const [transcript, setTranscript] = useState([]);
    const [analysis, setAnalysis] = useState(null);
    const [error, setError] = useState('');

    const [isPro, setIsPro] = useState(false);
    const [freeAiInterviewCount, setFreeAiInterviewCount] = useState(0);
    const navigate = useNavigate();

    // Check Pro limits on mount by fetching fresh data from backend
    useEffect(() => {
        const fetchProfile = async () => {
            try {
                const token = localStorage.getItem('token');
                if (!token) return;

                const res = await axios.get(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/users/profile`, {
                    headers: { Authorization: `Bearer ${token}` }
                });

                const user = res.data;
                setIsPro(user.hasProAccess || user.isPro === true);
                setFreeAiInterviewCount(user.freeAiInterviewCount || 0);

                // Keep local storage in sync with DB truth
                const localUserString = localStorage.getItem('user');
                let localUser;
                if (localUserString) {
                    try {
                        localUser = JSON.parse(localUserString);
                    } catch (e) {
                        localUser = {};
                    }
                } else {
                    localUser = {};
                }
                localUser.freeAiInterviewCount = user.freeAiInterviewCount;
                localUser.hasProAccess = user.hasProAccess;
                localUser.isPro = user.isPro;
                localStorage.setItem('user', JSON.stringify(localUser));
            } catch (err) {
                console.error("Failed to fetch fresh user profile", err);
                // Fallback to local storage if network request fails
                const userString = localStorage.getItem('user');
                if (userString) {
                    try {
                        const user = JSON.parse(userString);
                        setIsPro(user.hasProAccess || user.isPro === true);
                        setFreeAiInterviewCount(user.freeAiInterviewCount || 0);
                    } catch (e) { }
                }
            }
        };
        fetchProfile();
    }, []);

    const recognitionRef = useRef(null);
    const transcriptEndRef = useRef(null);
    const videoRef = useRef(null);
    const streamRef = useRef(null);

    // Scroll transcript to bottom
    useEffect(() => {
        transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [transcript]);

    // Handle Camera Stream
    useEffect(() => {
        if (stage === 'interviewing' && isCameraOn) {
            startCamera();
        } else {
            stopCamera();
        }
        return () => stopCamera();
    }, [stage, isCameraOn]);

    const startCamera = async () => {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: false });
            streamRef.current = stream;
            if (videoRef.current) {
                videoRef.current.srcObject = stream;
            }
        } catch (err) {
            console.error("Camera access denied", err);
            setError("Camera access denied. You can still continue with voice only.");
            setIsCameraOn(false);
        }
    };

    const stopCamera = () => {
        if (streamRef.current) {
            streamRef.current.getTracks().forEach(track => track.stop());
            streamRef.current = null;
        }
    };

    const handleCheckout = async () => {
        try {
            const token = localStorage.getItem('token');
            const { data: order } = await axios.post(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/payment/create-order`,
                { type: 'pro', amount: 99 },
                { headers: { Authorization: `Bearer ${token}` } }
            );

            const options = {
                key: import.meta.env.VITE_RAZORPAY_KEY_ID,
                amount: order.amount,
                currency: order.currency,
                name: "Dev2Dev",
                description: "Pro Interview Prep (1 Year Access)",
                order_id: order.id,
                handler: async function (response) {
                    try {
                        const verifyRes = await axios.post(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/payment/verify-payment`, {
                            razorpay_order_id: response.razorpay_order_id,
                            razorpay_payment_id: response.razorpay_payment_id,
                            razorpay_signature: response.razorpay_signature,
                            type: 'pro'
                        }, { headers: { Authorization: `Bearer ${token}` } });

                        if (verifyRes.data.isPro) {
                            setIsPro(true);
                            // Update local storage
                            const userString = localStorage.getItem('user');
                            if (userString) {
                                const user = JSON.parse(userString);
                                user.isPro = true;
                                user.hasProAccess = true;
                                localStorage.setItem('user', JSON.stringify(user));
                            }
                            alert("Payment Successful! You are now a Pro member.");
                        }
                    } catch (error) {
                        console.error("Payment verification failed", error);
                        alert("Payment verification failed.");
                    }
                },
                theme: {
                    color: "#6366f1"
                }
            };
            const rzp1 = new window.Razorpay(options);
            rzp1.on('payment.failed', function (response) {
                alert("Payment Failed: " + response.error.description);
            });
            rzp1.open();
        } catch (error) {
            console.error("Error initiating checkout:", error);
            alert("Could not initiate checkout. Please try again.");
        }
    };

    // Handle Resume Upload
    const handleResumeUpload = async (e) => {
        const file = e.target.files[0];
        if (!file) return;

        setIsUploading(true);
        setError('');
        const formData = new FormData();
        formData.append('file', file);

        try {
            const res = await axios.post(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/users/parse-resume`, formData);
            setResumeText(res.data.text);
        } catch (err) {
            setError('Failed to parse resume. Please try again.');
        } finally {
            setIsUploading(false);
        }
    };

    // Speech Recognition Setup
    const setupSpeech = () => {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        if (!SpeechRecognition) {
            alert("Your browser does not support speech recognition. Please use Chrome.");
            return null;
        }
        const recognition = new SpeechRecognition();
        recognition.continuous = false;
        recognition.interimResults = false;
        recognition.lang = 'en-US';

        recognition.onresult = (event) => {
            const text = event.results[0][0].transcript;
            handleUserResponse(text);
        };

        recognition.onerror = (event) => {
            console.error("Speech Recognition Error", event.error);
            setIsRecording(false);
        };

        recognition.onend = () => {
            setIsRecording(false);
        };

        return recognition;
    };

    // AI Voice Synthesis
    const speakText = (text) => {
        const utterance = new SpeechSynthesisUtterance(text);
        utterance.rate = 1;
        utterance.pitch = 1;
        window.speechSynthesis.speak(utterance);
    };

    // Start Phase
    const startInterview = async () => {
        if (!jobProfile || !resumeText) {
            setError('Please provide both Job Profile and Resume.');
            return;
        }
        setStage('interviewing');
        setTranscript([]);

        // Initial Greeting from AI
        const greeting = `Hello! I see you are applying for the ${jobProfile} position. I've reviewed your resume. Let's start the interview. Can you tell me a bit about your experience related to this role?`;
        setTranscript([{ role: 'interviewer', text: greeting }]);
        speakText(greeting);
    };

    // Capture User Voice
    const toggleRecording = () => {
        if (isRecording) {
            recognitionRef.current.stop();
        } else {
            if (!recognitionRef.current) {
                recognitionRef.current = setupSpeech();
            }
            recognitionRef.current.start();
            setIsRecording(true);
        }
    };

    // Process User Input -> AI Output
    const handleUserResponse = async (text) => {
        const newTranscript = [...transcript, { role: 'user', text }];
        setTranscript(newTranscript);
        setIsAITyping(true);

        try {
            // Get AI Response from Python Backend
            const response = await fetch(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/users/interview-chat`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    message: text,
                    role: jobProfile,
                    resume_context: resumeText,
                    transcript: newTranscript
                })
            });

            const reader = response.body.getReader();
            const decoder = new TextDecoder();
            let aiMsg = '';

            // Temporary message object to update
            setTranscript(prev => [...prev, { role: 'interviewer', text: '' }]);

            while (true) {
                const { done, value } = await reader.read();
                if (done) break;
                const chunk = decoder.decode(value);
                aiMsg += chunk;

                setTranscript(prev => {
                    const last = [...prev];
                    last[last.length - 1].text = aiMsg;
                    return last;
                });
            }

            // Speak the completed AI message
            speakText(aiMsg);

        } catch (err) {
            console.error(err);
        } finally {
            setIsAITyping(false);
        }
    };

    // Finish & Eval
    const finishInterview = async () => {
        window.speechSynthesis.cancel(); // Stop talking
        setStage('analysing');
        try {
            // 1. Get AI Evaluation from Python Service
            const res = await axios.post(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/users/mock-interview-eval`, {
                domain: jobProfile,
                role: jobProfile,
                transcript: transcript
            });
            const evalData = res.data;
            setAnalysis(evalData);

            // 2. Save result to Node.js Backend for persistence
            try {
                await axios.post(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/interviews`, {
                    role: jobProfile,
                    domain: jobProfile,
                    score: evalData.score,
                    technicalScore: evalData.technical,
                    communicationScore: evalData.communication,
                    hireProbability: evalData.hireProbability,
                    feedback: evalData.feedback,
                    improvements: evalData.improvements,
                    studyPlan: evalData.studyPlan,
                    transcript: transcript
                }, {
                    headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
                });
                console.log('✅ Interview result saved to dashboard');

                // Update local storage so the UI reflects the attempt immediately
                const userString = localStorage.getItem('user');
                if (userString) {
                    try {
                        const userObj = JSON.parse(userString);
                        if (!userObj.hasProAccess && !userObj.isPro) {
                            userObj.freeAiInterviewCount = (userObj.freeAiInterviewCount || 0) + 1;
                            localStorage.setItem('user', JSON.stringify(userObj));
                            setFreeAiInterviewCount(userObj.freeAiInterviewCount);
                        }
                    } catch (e) {
                        console.error("Error updating local storage", e);
                    }
                }
            } catch (err) {
                console.warn('❌ Failed to save interview to dashboard:', err);
                // We still show the results even if saving fails
            }

            setStage('results');
        } catch (err) {
            setError('Evaluation failed. Please try again.');
            setStage('interviewing');
        }
    };

    // ── Setup Stage UI ──
    if (stage === 'setup') {
        return (
            <div className="interview-container animate-fade-in">
                <div className="setup-header">
                    <h1 style={{
                        fontSize: '2.5rem',
                        fontWeight: 850,
                        marginBottom: '0.5rem',
                        color: '#fff',
                        letterSpacing: '-1.5px'
                    }}>
                        AI Mock Interview
                    </h1>
                    <p style={{ fontSize: '1.1rem', color: 'rgba(255,255,255,0.4)', maxWidth: '600px', lineHeight: 1.6 }}>
                        Simulate high-pressure technical interviews with our neural engine and get real-time feedback.
                    </p>
                </div>

                <div className="card glass-panel" style={{ padding: '3rem', borderRadius: '32px', border: '1px solid rgba(255,255,255,0.1)', boxShadow: '0 40px 100px rgba(0,0,0,0.4)', position: 'relative', overflow: 'hidden' }}>
                    <div style={{ position: 'absolute', top: 0, right: 0, width: '200px', height: '200px', background: 'radial-gradient(circle, rgba(99, 102, 241, 0.05) 0%, transparent 70%)', pointerEvents: 'none' }}></div>

                    <div className="form-group" style={{ marginBottom: '2.5rem' }}>
                        <label style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '1rem', fontWeight: 700, color: '#fff', fontSize: '0.95rem' }}>
                            <div style={{ padding: '0.5rem', borderRadius: '8px', background: 'rgba(255,255,255,0.03)' }}><Briefcase size={18} className="text-muted" /></div>
                            Job Profile you're targeting
                        </label>
                        <input
                            type="text"
                            placeholder="e.g. Senior Frontend Engineer, DevOps Specialist..."
                            value={jobProfile}
                            onChange={(e) => setJobProfile(e.target.value)}
                            className="glass-input-premium"
                            style={{ width: '100%', padding: '1.25rem 1.5rem', background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.15)', borderRadius: '16px', color: '#fff', fontSize: '1rem', fontWeight: '500', transition: '0.3s', outline: 'none' }}
                        />
                    </div>

                    <div className="form-group" style={{ marginBottom: '3rem' }}>
                        <label style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '1rem', fontWeight: 700, color: '#fff', fontSize: '0.95rem' }}>
                            <div style={{ padding: '0.5rem', borderRadius: '8px', background: 'rgba(255,255,255,0.03)' }}><FileText size={18} className="text-muted" /></div>
                            Resume Data (Optional but Recommended)
                        </label>
                        {!resumeText ? (
                            <label className={`upload-zone-premium flex-center`} style={{ flexDirection: 'column', height: '200px', border: '2px dashed rgba(255,255,255,0.05)', borderRadius: '24px', cursor: 'pointer', background: 'rgba(255,255,255,0.01)', transition: '0.4s cubic-bezier(0.165, 0.84, 0.44, 1)' }}>
                                {isUploading ? (
                                    <>
                                        <Loader2 className="animate-spin" size={40} color="var(--accent-primary)" />
                                        <p style={{ marginTop: '1.5rem', fontWeight: 600 }}>Analyzing resume structure...</p>
                                    </>
                                ) : (
                                    <>
                                        <div style={{ width: '60px', height: '60px', borderRadius: '50%', background: 'rgba(99, 102, 241, 0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: '1rem' }}>
                                            <UploadCloud size={28} color="var(--accent-primary)" />
                                        </div>
                                        <p style={{ fontWeight: 700, fontSize: '1.1rem' }}>Upload your Resume</p>
                                        <p className="text-muted" style={{ fontSize: '0.9rem', marginTop: '0.25rem' }}>PDF or DOCX supported (Maximum 5MB)</p>
                                        <input type="file" hidden accept=".pdf,.docx" onChange={handleResumeUpload} />
                                    </>
                                )}
                            </label>
                        ) : (
                            <div className="flex-between glass-panel" style={{ padding: '1.5rem 2rem', borderRadius: '20px', background: 'rgba(129, 140, 248, 0.05)', border: '1px solid rgba(129, 140, 248, 0.1)' }}>
                                <div className="flex-center" style={{ gap: '1rem' }}>
                                    <div style={{ width: '40px', height: '40px', borderRadius: '50%', background: 'rgba(129, 140, 248, 0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                        <CheckCircle size={20} color="#818cf8" />
                                    </div>
                                    <div>
                                        <p style={{ fontWeight: 700, color: '#818cf8' }}>Resume Analyzed</p>
                                        <p style={{ fontSize: '0.8rem', opacity: 0.6 }}>Contextual questions enabled</p>
                                    </div>
                                </div>
                                <button style={{ background: 'none', border: 'none', color: '#ef4444', fontWeight: 600, cursor: 'pointer' }} onClick={() => setResumeText('')}>Remove</button>
                            </div>
                        )}
                    </div>

                    {error && (
                        <div style={{ color: '#ef4444', background: 'rgba(239, 68, 68, 0.1)', padding: '1rem', borderRadius: '12px', marginBottom: '2rem', display: 'flex', alignItems: 'center', gap: '0.75rem', fontSize: '0.9rem' }}>
                            <AlertCircle size={18} /> {error}
                        </div>
                    )}

                    {!isPro && freeAiInterviewCount >= 3 ? (
                        <div className="flex-center" style={{ flexDirection: 'column', gap: '1rem', background: 'rgba(255, 255, 255, 0.02)', padding: '2rem', borderRadius: '16px', border: '1px solid rgba(255,255,255,0.05)' }}>
                            <Lock size={32} style={{ color: 'rgba(255,255,255,0.4)', marginBottom: '0.5rem' }} />
                            <h3 style={{ margin: 0, fontSize: '1.2rem', fontWeight: 700 }}>Free Limit Reached (3/3)</h3>
                            <p className="text-muted" style={{ textAlign: 'center', maxWidth: '400px', fontSize: '0.95rem' }}>
                                You have used all your free AI Mock Interviews. Upgrade to Pro for unlimited sessions and full access to Company Playloads.
                            </p>
                            <button
                                className="premium-btn"
                                onClick={handleCheckout}
                                style={{
                                    marginTop: '0.5rem',
                                    padding: '0.75rem 1.5rem',
                                    borderRadius: '100px',
                                    background: 'linear-gradient(45deg, var(--accent-primary), #ff00ff)',
                                    border: 'none',
                                    color: '#fff',
                                    fontWeight: 700,
                                    fontSize: '0.9rem',
                                    display: 'flex',
                                    alignItems: 'center',
                                    gap: '0.5rem',
                                    cursor: 'pointer',
                                    boxShadow: '0 4px 15px rgba(99, 102, 241, 0.4)'
                                }}
                            >
                                <Trophy size={18} /> Get Pro for ₹99 (1 Year Access)
                            </button>
                        </div>
                    ) : (
                        <div>
                            {!isPro && (
                                <div style={{ marginBottom: '1rem', textAlign: 'center' }}>
                                    <span style={{ fontSize: '0.8rem', fontWeight: 600, color: 'var(--text-secondary)', background: 'rgba(255,255,255,0.05)', padding: '0.4rem 0.8rem', borderRadius: '20px' }}>
                                        {3 - freeAiInterviewCount} Free Attempts Remaining
                                    </span>
                                </div>
                            )}
                            <button
                                className="btn-premium-large flex-center"
                                style={{ width: '100%', padding: '1.25rem', fontSize: '1.1rem', gap: '1rem' }}
                                onClick={startInterview}
                                disabled={!jobProfile}
                            >
                                Enter Interview Room <ArrowRight size={20} />
                            </button>
                        </div>
                    )}
                </div>

                <style>{`
                    .glass-input-premium:focus {
                        background: rgba(255,255,255,0.04);
                        border-color: var(--accent-primary);
                        box-shadow: 0 0 20px rgba(99, 102, 241, 0.15);
                    }
                    .upload-zone-premium:hover {
                        border-color: var(--accent-primary) !important;
                        background: rgba(99, 102, 241, 0.05) !important;
                        transform: translateY(-2px);
                    }
                    .btn-premium-large {
                        background: linear-gradient(135deg, var(--accent-primary), #818cf8);
                        color: #fff;
                        border: none;
                        border-radius: 16px;
                        font-weight: 800;
                        cursor: pointer;
                        transition: 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
                        box-shadow: 0 10px 30px rgba(99, 102, 241, 0.4);
                    }
                    .btn-premium-large:hover:not(:disabled) {
                        transform: scale(1.02);
                        box-shadow: 0 15px 40px rgba(99, 102, 241, 0.6);
                    }
                    .btn-premium-large:disabled {
                        opacity: 0.3;
                        cursor: not-allowed;
                        filter: grayscale(1);
                    }
                `}</style>
            </div>
        );
    }

    // ── Interviewing Stage UI ──
    if (stage === 'interviewing') {
        return (
            <div className="interview-container interviewing-layout animate-fade-in">

                {/* Visualizer & Camera Section */}
                <div className="video-section">
                    <div className="video-feed-container">

                        {isCameraOn ? (
                            <div style={{ width: '100%', height: '100%', position: 'relative' }}>
                                <video
                                    ref={videoRef}
                                    autoPlay
                                    playsInline
                                    muted
                                    style={{ width: '100%', height: '100%', objectFit: 'cover', transform: 'scaleX(-1)', borderRadius: '24px' }}
                                />

                                {/* Professional HUD/Viewfinder Overlay */}
                                <div style={{ position: 'absolute', inset: '2rem', border: '1px solid rgba(255,255,255,0.1)', pointerEvents: 'none', borderRadius: '12px' }}>
                                    <div style={{ position: 'absolute', top: 0, left: 0, width: '20px', height: '20px', borderTop: '2px solid var(--accent-primary)', borderLeft: '2px solid var(--accent-primary)' }} />
                                    <div style={{ position: 'absolute', top: 0, right: 0, width: '20px', height: '20px', borderTop: '2px solid var(--accent-primary)', borderRight: '2px solid var(--accent-primary)' }} />
                                    <div style={{ position: 'absolute', bottom: 0, left: 0, width: '20px', height: '20px', borderBottom: '2px solid var(--accent-primary)', borderLeft: '2px solid var(--accent-primary)' }} />
                                    <div style={{ position: 'absolute', bottom: 0, right: 0, width: '20px', height: '20px', borderBottom: '2px solid var(--accent-primary)', borderRight: '2px solid var(--accent-primary)' }} />

                                    <div style={{ position: 'absolute', top: '50%', left: '1rem', height: '100px', width: '2px', background: 'rgba(255,255,255,0.1)', transform: 'translateY(-50%)' }}>
                                        <div style={{ position: 'absolute', top: '20%', left: '-4px', width: '10px', height: '2px', background: 'var(--accent-primary)' }} />
                                    </div>
                                </div>

                                <div style={{ position: 'absolute', bottom: '1.5rem', left: '1.5rem', background: 'rgba(0,0,0,0.7)', backdropFilter: 'blur(10px)', padding: '0.6rem 1.2rem', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.1)', boxShadow: '0 8px 32px rgba(0,0,0,0.4)' }}>
                                    <p style={{ fontSize: '0.75rem', fontWeight: 700, color: 'var(--accent-primary)', margin: 0, letterSpacing: '1px' }}>CANDIDATE: YOU</p>
                                </div>

                                <div style={{ position: 'absolute', top: '1.5rem', right: '1.5rem', display: 'flex', alignItems: 'center', gap: '0.5rem', background: 'rgba(239, 68, 68, 0.2)', padding: '0.4rem 0.8rem', borderRadius: '20px', border: '1px solid rgba(239, 68, 68, 0.3)' }}>
                                    <div className="pulse-dot" style={{ background: '#ef4444' }} />
                                    <span style={{ fontSize: '0.7rem', fontWeight: 800, color: '#ef4444' }}>REC • LIVE</span>
                                </div>
                            </div>
                        ) : (
                            <div style={{ textAlign: 'center', padding: '2rem' }}>
                                <div className={`avatar-pulse ${isAITyping ? 'active' : ''}`} style={{ width: '180px', height: '180px', borderRadius: '50%', background: 'linear-gradient(135deg, var(--accent-primary), var(--accent-secondary))', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', margin: '0 auto', boxShadow: '0 0 50px rgba(99, 102, 241, 0.3)' }}>
                                    <User size={80} />
                                </div>
                                <h2 style={{ marginTop: '2.5rem', letterSpacing: '3px', fontWeight: 900, textTransform: 'uppercase', color: 'rgba(255,255,255,0.9)' }}>Interview Room</h2>
                                <p className="text-muted" style={{ marginTop: '1rem' }}>Camera is currently disabled</p>
                            </div>
                        )}

                        {isAITyping && (
                            <div style={{ position: 'absolute', bottom: '2rem', right: '2rem', background: 'rgba(99, 102, 241, 0.95)', padding: '0.8rem 1.5rem', borderRadius: '16px', display: 'flex', alignItems: 'center', gap: '0.75rem', boxShadow: '0 10px 40px rgba(99, 102, 241, 0.4)', border: '1px solid rgba(255,255,255,0.2)', animation: 'slideUp 0.3s ease-out' }}>
                                <Loader2 size={20} className="spin" />
                                <span style={{ fontSize: '0.9rem', fontWeight: 700 }}>Dev2Dev AI is thinking...</span>
                            </div>
                        )}
                    </div>

                    {/* Control Bar - Glassmorphic */}
                    <div className="control-bar">
                        <div style={{ display: 'flex', gap: '1.25rem' }}>
                            <button
                                className={`mic-btn ${isRecording ? 'recording' : ''}`}
                                onClick={toggleRecording}
                                disabled={isAITyping}
                                style={{
                                    width: '64px', height: '64px', borderRadius: '50%', border: 'none',
                                    background: isRecording ? '#ef4444' : (isAITyping ? 'rgba(255,255,255,0.05)' : 'var(--accent-primary)'),
                                    color: '#fff', cursor: isAITyping ? 'not-allowed' : 'pointer',
                                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                                    transition: 'all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275)',
                                    boxShadow: isRecording ? '0 0 30px rgba(239, 68, 68, 0.4)' : '0 10px 25px rgba(0,0,0,0.2)'
                                }}
                            >
                                {isRecording ? <MicOff size={28} /> : <Mic size={28} />}
                            </button>

                            <button
                                onClick={() => setIsCameraOn(!isCameraOn)}
                                style={{
                                    width: '64px', height: '64px', borderRadius: '20px', border: '1px solid rgba(255,255,255,0.1)',
                                    background: isCameraOn ? 'rgba(99, 102, 241, 0.15)' : 'rgba(255,255,255,0.05)',
                                    color: isCameraOn ? 'var(--accent-primary)' : '#fff', cursor: 'pointer',
                                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                                    transition: 'all 0.3s'
                                }}
                            >
                                {isCameraOn ? <Video size={28} /> : <VideoOff size={28} />}
                            </button>
                        </div>

                        <div style={{ textAlign: 'center' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', justifyContent: 'center', marginBottom: '0.25rem' }}>
                                <Waveform active={isRecording || isAITyping} color={isRecording ? '#ef4444' : 'var(--accent-primary)'} />
                                <p style={{ fontWeight: 800, margin: 0, fontSize: '1.2rem', color: isRecording ? '#ef4444' : '#fff', letterSpacing: '0.5px' }}>
                                    {isRecording ? 'LISTENING' : (isAITyping ? 'AI SPEAKING' : 'IDLE')}
                                </p>
                                <Waveform active={isRecording || isAITyping} color={isRecording ? '#ef4444' : 'var(--accent-primary)'} />
                            </div>
                            <p style={{ margin: 0, fontSize: '0.75rem', opacity: 0.5, fontWeight: 600, textTransform: 'uppercase', letterSpacing: '1px' }}>
                                {isRecording ? 'Capturing High-Fidelity Audio' : 'Speak clearly and confidently'}
                            </p>
                        </div>

                        <button
                            className="btn"
                            style={{
                                background: 'rgba(239, 68, 68, 0.1)',
                                color: '#ef4444',
                                border: '1px solid rgba(239, 68, 68, 0.2)',
                                padding: '0.8rem 1.5rem',
                                borderRadius: '14px',
                                fontWeight: 700,
                                fontSize: '0.9rem'
                            }}
                            onClick={finishInterview}
                        >
                            Complete Session
                        </button>
                    </div>
                </div>

                {/* AI & Transcript Sidebar */}
                <div className="transcript-sidebar">

                    {/* AI Profile Card */}
                    <div className="card glass-panel" style={{ padding: '1.5rem', background: 'linear-gradient(135deg, rgba(99, 102, 241, 0.1), rgba(168, 85, 247, 0.1))', border: '1px solid rgba(255,255,255,0.1)' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                            <div style={{ position: 'relative' }}>
                                <div style={{ width: '56px', height: '56px', borderRadius: '16px', background: 'var(--accent-primary)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                    <Loader2 className={isAITyping ? 'spin' : ''} size={28} color="#fff" />
                                </div>
                                <div style={{ position: 'absolute', bottom: '-4px', right: '-4px', width: '16px', height: '16px', borderRadius: '50%', background: '#818cf8', border: '3px solid #0f172a' }} />
                            </div>
                            <div>
                                <h4 style={{ margin: 0, fontWeight: 800 }}>Dev2Dev AI</h4>
                                <p style={{ margin: 0, fontSize: '0.7rem', opacity: 0.6, fontWeight: 700, textTransform: 'uppercase' }}>Senior Technical Interviewer</p>
                            </div>
                        </div>
                    </div>

                    <div className="card glass-panel" style={{ flex: 1, display: 'flex', flexDirection: 'column', padding: '1.5rem', overflow: 'hidden' }}>
                        <div className="flex-between" style={{ marginBottom: '1.5rem', borderBottom: '1px solid rgba(255,255,255,0.05)', paddingBottom: '1rem' }}>
                            <h3 style={{ display: 'flex', alignItems: 'center', gap: '0.6rem', fontSize: '1.1rem' }}>
                                <RefreshCw size={18} className={isAITyping ? 'spin' : ''} style={{ color: 'var(--accent-primary)' }} /> Live Transcript
                            </h3>
                            <span style={{ fontSize: '0.7rem', background: 'rgba(255,255,255,0.05)', padding: '0.3rem 0.6rem', borderRadius: '8px', fontWeight: 800 }}>{transcript.length} TURNS</span>
                        </div>

                        <div style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: '1rem', paddingRight: '0.5rem' }}>
                            {transcript.map((msg, idx) => (
                                <div key={idx} className={`msg-bubble ${msg.role} animate-fade-in`} style={{
                                    padding: '1.25rem',
                                    borderRadius: '18px',
                                    background: msg.role === 'interviewer' ? 'rgba(255,255,255,0.04)' : 'rgba(99, 102, 241, 0.15)',
                                    border: '1px solid rgba(255,255,255,0.05)',
                                    borderLeft: msg.role === 'interviewer' ? '4px solid var(--accent-primary)' : '1px solid rgba(255,255,255,0.05)',
                                    borderRight: msg.role === 'user' ? '4px solid #818cf8' : '1px solid rgba(255,255,255,0.05)',
                                    alignSelf: msg.role === 'interviewer' ? 'flex-start' : 'flex-end',
                                    width: '95%',
                                    position: 'relative'
                                }}>
                                    <div style={{ fontSize: '0.65rem', fontWeight: 900, textTransform: 'uppercase', color: msg.role === 'interviewer' ? 'var(--accent-primary)' : '#818cf8', marginBottom: '0.5rem', letterSpacing: '1px' }}>
                                        {msg.role === 'interviewer' ? 'Dev2Dev AI' : 'Your Answer'}
                                    </div>
                                    <div style={{ fontSize: '0.95rem', lineHeight: 1.6, color: 'rgba(255,255,255,0.9)' }}>{msg.text}</div>
                                </div>
                            ))}
                            <div ref={transcriptEndRef} />
                        </div>
                    </div>
                </div>

                <style>{`
                    @keyframes slideUp { from { transform: translateY(20px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
                    .avatar-pulse.active { animation: avatarPulse 2s infinite; }
                    @keyframes avatarPulse {
                        0% { transform: scale(1); box-shadow: 0 0 0 0 rgba(99, 102, 241, 0.7); }
                        70% { transform: scale(1.05); box-shadow: 0 0 0 40px rgba(99, 102, 241, 0); }
                        100% { transform: scale(1); box-shadow: 0 0 0 0 rgba(99, 102, 241, 0); }
                    }
                    .mic-btn.recording { animation: recPulse 1s infinite alternate; }
                    @keyframes recPulse { 
                        from { transform: scale(1); opacity: 1; } 
                        to { transform: scale(1.15); opacity: 0.9; } 
                    }
                    .pulse-dot { width: 10px; height: 10px; borderRadius: 50%; animation: blink 1s infinite; }
                    @keyframes blink { 0%, 100% { opacity: 1; } 50% { opacity: 0.3; } }
                `}</style>
            </div>
        );
    }

    // ── Analyzing Stage ──
    if (stage === 'analysing') {
        return (
            <div className="container flex-center" style={{ height: '80vh', flexDirection: 'column', position: 'relative' }}>
                <div style={{ position: 'absolute', inset: 0, background: 'radial-gradient(circle at center, rgba(99, 102, 241, 0.05) 0%, transparent 70%)', pointerEvents: 'none' }} />
                <div style={{ position: 'relative', width: '160px', height: '160px', display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: '3rem' }}>
                    <div className="spin-slow" style={{ position: 'absolute', width: '100%', height: '100%', borderRadius: '50%', border: '2px dashed rgba(99, 102, 241, 0.3)' }} />
                    <div style={{ position: 'absolute', width: '80%', height: '80%', borderRadius: '50%', border: '4px solid rgba(99, 102, 241, 0.1)', borderTopColor: 'var(--accent-primary)', animation: 'spin 1.5s cubic-bezier(0.5, 0, 0.5, 1) infinite' }} />
                    <Loader2 size={48} className="spin" color="var(--accent-primary)" />
                </div>
                <h2 style={{ fontWeight: 900, fontSize: '2rem', letterSpacing: '-0.5px', marginBottom: '0.5rem' }}>Synthesizing Feedback</h2>
                <p className="text-muted" style={{ fontSize: '1.1rem' }}>Dev2Dev Neural Engine is processing your technical depth...</p>
            </div>
        );
    }

    if (stage === 'results' && analysis) {
        return (
            <div className="container animate-fade-in" style={{ padding: '2rem 1.5rem', maxWidth: '1100px' }}>

                {/* Header Section */}
                <div className="card glass-panel animate-fade-in" style={{
                    padding: '3rem 2rem',
                    marginBottom: '2rem',
                    background: 'linear-gradient(135deg, rgba(15, 15, 25, 0.95) 0%, rgba(99, 102, 241, 0.05) 100%)',
                    border: '1px solid rgba(255,255,255,0.05)',
                    position: 'relative',
                    overflow: 'hidden'
                }}>
                    <div className="results-header-flex">
                        <div style={{ textAlign: 'left' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1rem' }}>
                                <div style={{ background: 'rgba(129, 140, 248, 0.1)', color: '#818cf8', padding: '0.5rem 1rem', borderRadius: '50px', fontSize: '0.75rem', fontWeight: 800, border: '1px solid rgba(129, 140, 248, 0.2)' }}>
                                    SESSION COMPLETE
                                </div>
                                <span style={{ opacity: 0.4, fontSize: '0.8rem' }}>• {new Date().toLocaleDateString()}</span>
                            </div>
                            <h1 style={{ fontSize: '3.5rem', fontWeight: 900, letterSpacing: '-2px', marginBottom: '0.5rem' }}>Interview Insights</h1>
                            <p className="text-muted" style={{ fontSize: '1.2rem' }}>Technical evaluation for <span style={{ color: 'var(--accent-primary)', fontWeight: 800 }}>{jobProfile}</span></p>
                        </div>

                        <div style={{ textAlign: 'right' }}>
                            <div style={{
                                padding: '1.5rem 2.5rem',
                                background: analysis.hireProbability === 'High' ? 'rgba(129, 140, 248, 0.1)' : 'rgba(251, 191, 36, 0.1)',
                                borderRadius: '24px',
                                border: `1px solid ${analysis.hireProbability === 'High' ? 'rgba(129, 140, 248, 0.2)' : 'rgba(251, 191, 36, 0.2)'}`
                            }}>
                                <p style={{ fontSize: '0.75rem', fontWeight: 800, opacity: 0.6, marginBottom: '0.5rem', textTransform: 'uppercase' }}>Hiring Status</p>
                                <h2 style={{ fontSize: '2.5rem', fontWeight: 900, color: analysis.hireProbability === 'High' ? '#818cf8' : '#fbbf24', margin: 0 }}>{analysis.hireProbability}</h2>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Score Dashboard */}
                <div className="results-grid">
                    <StatRing value={analysis.score} label="Overall Match" color="var(--accent-primary)" icon={CheckCircle} />
                    <StatRing value={analysis.technical} label="Technical Depth" color="#818cf8" icon={Briefcase} />
                    <StatRing value={analysis.communication} label="Communication" color="#c084fc" icon={Volume2} />

                    {/* Achievement Badges Card */}
                    <div className="glass-panel" style={{ padding: '1.5rem', borderRadius: '24px', background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.05)' }}>
                        <span style={{ fontSize: '0.75rem', fontWeight: 800, opacity: 0.5, textTransform: 'uppercase', letterSpacing: '1px' }}>Achievements</span>
                        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '1rem', marginTop: '1rem' }}>
                            <div className="badge-item" title="Technical Titan" style={{ textAlign: 'center' }}>
                                <div style={{ width: '45px', height: '45px', background: 'rgba(99, 102, 241, 0.1)', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 0.5rem', color: 'var(--accent-primary)', border: '1px solid rgba(99, 102, 241, 0.2)' }}>
                                    <Briefcase size={20} />
                                </div>
                                <span style={{ fontSize: '0.65rem', fontWeight: 700 }}>Pro Level</span>
                            </div>
                            <div className="badge-item" title="Quick Thinker" style={{ textAlign: 'center' }}>
                                <div style={{ width: '45px', height: '45px', background: 'rgba(129, 140, 248, 0.1)', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 0.5rem', color: '#818cf8', border: '1px solid rgba(129, 140, 248, 0.2)' }}>
                                    <RefreshCw size={20} />
                                </div>
                                <span style={{ fontSize: '0.65rem', fontWeight: 700 }}>Fast Response</span>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="results-detail-grid">
                    <div className="card glass-panel" style={{ padding: '2.5rem', background: 'rgba(255,255,255,0.01)', position: 'relative' }}>
                        <div style={{ position: 'absolute', top: '1.5rem', right: '1.5rem', opacity: 0.1 }}>
                            <Zap size={60} />
                        </div>
                        <h3 style={{ display: 'flex', alignItems: 'center', gap: '0.8rem', marginBottom: '2rem', fontSize: '1.4rem' }}>
                            <Cpu color="var(--accent-primary)" size={24} /> Neural Feedback Engine
                        </h3>
                        <p style={{ lineHeight: 1.8, fontSize: '1.1rem', opacity: 0.9, position: 'relative', zIndex: 1 }}>{analysis.feedback}</p>

                        <div style={{ marginTop: '3rem' }}>
                            <h4 style={{ display: 'flex', alignItems: 'center', gap: '0.6rem', color: '#f87171', fontSize: '0.9rem', textTransform: 'uppercase', fontWeight: 800, letterSpacing: '1px', marginBottom: '1.5rem' }}>
                                <AlertTriangle size={18} /> Optimization Required
                            </h4>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                                {analysis.improvements?.map((item, i) => (
                                    <div key={i} style={{ padding: '1rem 1.5rem', background: 'rgba(239, 68, 68, 0.05)', borderRadius: '15px', border: '1px solid rgba(239, 68, 68, 0.1)', fontSize: '0.95rem' }}>
                                        {item}
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>

                    <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                        <div className="card glass-panel" style={{ padding: '2rem', background: 'linear-gradient(135deg, rgba(99, 102, 241, 0.1), transparent)', border: '1px solid rgba(99, 102, 241, 0.2)' }}>
                            <h3 style={{ color: '#818cf8', marginBottom: '1.5rem', display: 'flex', alignItems: 'center', gap: '0.6rem' }}>
                                <BookOpen size={20} /> Accelerated Study Plan
                            </h3>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                                {analysis.studyPlan?.map((topic, i) => (
                                    <div key={topic} style={{ padding: '1.25rem', background: 'rgba(0,0,0,0.3)', border: '1px solid rgba(255,255,255,0.05)', borderRadius: '16px', display: 'flex', alignItems: 'center', gap: '1rem' }}>
                                        <div style={{ width: '32px', height: '32px', borderRadius: '50%', background: 'var(--accent-primary)', color: '#fff', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 900, fontSize: '0.8rem' }}>{i + 1}</div>
                                        <span style={{ fontWeight: 600 }}>{topic}</span>
                                    </div>
                                ))}
                            </div>
                        </div>

                        <button
                            className="btn"
                            style={{
                                marginTop: 'auto',
                                padding: '1.5rem',
                                borderRadius: '20px',
                                background: 'var(--accent-primary)',
                                color: '#fff',
                                fontWeight: 900,
                                fontSize: '1.1rem',
                                boxShadow: '0 10px 40px rgba(99, 102, 241, 0.3)',
                                transition: '0.3s'
                            }}
                            onClick={() => setStage('setup')}
                        >
                            RESTART SIMULATION
                        </button>
                    </div>
                </div>

                <style>{`
                    @keyframes wave {
                        0%, 100% { height: 4px; }
                        50% { height: 25px; }
                    }
                    @keyframes slideUp { from { transform: translateY(20px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
                    @keyframes spin-slow { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
                    .spin-slow { animation: spin-slow 8s linear infinite; }
                    
                    .stat-ring-container:hover {
                        background: rgba(255,255,255,0.05) !important;
                        transform: translateY(-5px);
                        border-color: rgba(99, 102, 241, 0.3) !important;
                    }
                    
                    .badge-item:hover div {
                        transform: scale(1.1) rotate(5deg);
                        box-shadow: 0 0 20px rgba(99, 102, 241, 0.3);
                    }

                    .avatar-pulse.active { animation: avatarPulse 2s infinite; }
                    @keyframes avatarPulse {
                        0% { transform: scale(1); box-shadow: 0 0 0 0 rgba(99, 102, 241, 0.7); }
                        70% { transform: scale(1.05); box-shadow: 0 0 0 40px rgba(99, 102, 241, 0); }
                        100% { transform: scale(1); box-shadow: 0 0 0 0 rgba(99, 102, 241, 0); }
                    }
                    .mic-btn.recording { animation: recPulse 1s infinite alternate; }
                    @keyframes recPulse { 
                        from { transform: scale(1); opacity: 1; } 
                        to { transform: scale(1.15); opacity: 0.9; } 
                    }
                    .pulse-dot { width: 10px; height: 10px; borderRadius: 50%; animation: blink 1s infinite; }
                    @keyframes blink { 0%, 100% { opacity: 1; } 50% { opacity: 0.3; } }
                `}</style>
            </div>
        );
    }

    return null;
};

export default MockInterview;

import React from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { ChevronLeft, HelpCircle, FileText, Clock, Award, Sparkles } from 'lucide-react';
import { generateCertificate, isEligibleForCertificate } from '../utils/certificateGenerator';

const MockReport = () => {
    const location = useLocation();
    const navigate = useNavigate();

    // In a real app, we'd fetch this by ID if state isn't present
    const { report, timeSpent } = location.state || {};

    if (!report) {
        return (
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '100vh', background: '#f3f4f6' }}>
                <h2>No report data found.</h2>
                <button onClick={() => navigate('/interview-prep')} style={{ marginTop: '1rem', padding: '0.5rem 1rem', cursor: 'pointer' }}>Go Back</button>
            </div>
        );
    }

    const formatTime = (seconds) => {
        const m = Math.floor((seconds % 3600) / 60);
        const s = seconds % 60;
        return `${m} minutes ${s} seconds`;
    };

    const handleDownloadCertificate = () => {
        if (!report) return;

        const userStr = localStorage.getItem('user');
        const userData = userStr ? JSON.parse(userStr) : { name: 'Elevate User' };

        generateCertificate(userData, {
            examName: report.examName,
            score: report.score,
            totalMarks: report.totalMarks,
            dateRun: report.dateRun
        }, 'EXAM');
    };

    const statusStyle = (passed) => {
        if (report.score === 0) return { color: '#666', bg: '#f3f4f6', text: 'Skipped' };
        return passed ? { color: '#818cf8', bg: '#d1fae5', text: 'Accepted' } : { color: '#ef4444', bg: '#fee2e2', text: 'Rejected' };
    };

    return (
        <div style={{ minHeight: '100vh', background: '#f9fafb', fontFamily: 'Inter, sans-serif' }}>
            <div style={{ background: '#fff', borderBottom: '1px solid #e5e7eb', padding: '1rem 2rem' }}>
                <div style={{ maxWidth: '1200px', margin: '0 auto', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <button
                        onClick={() => navigate('/interview-prep')}
                        style={{ display: 'flex', alignItems: 'center', gap: '0.25rem', background: 'transparent', border: 'none', color: '#6b7280', fontSize: '0.9rem', cursor: 'pointer' }}
                    >
                        <ChevronLeft size={16} /> Return to My Overview
                    </button>
                    <div style={{ flex: 1 }}></div>
                </div>
            </div>

            <div style={{ maxWidth: '1200px', margin: '0 auto', padding: '2rem' }}>
                <h1 style={{ fontSize: '2.5rem', fontWeight: 700, margin: '0 0 0.5rem 0', color: '#111827' }}>Reports</h1>
                <p style={{ color: '#6b7280', fontSize: '1.1rem', margin: '0 0 2rem 0' }}>View detailed stats of your previous mock assessments</p>

                <div style={{ display: 'flex', gap: '2rem' }}>

                    {/* Left Sidebar - Past History Placeholder */}
                    <div style={{ width: '300px', background: '#fff', borderRadius: '8px', border: '1px solid #e5e7eb', flexShrink: 0, overflow: 'hidden' }}>
                        <div style={{ padding: '1rem', borderBottom: '1px solid #e5e7eb', fontWeight: 600, color: '#374151' }}>
                            Past Mock Assessments
                        </div>
                        <div style={{ padding: '1rem', display: 'flex', alignItems: 'flex-start', gap: '1rem', background: '#f9fafb', borderLeft: '3px solid #f59e0b' }}>
                            <div style={{ background: '#fef3c7', color: '#d97706', borderRadius: '50%', width: '24px', height: '24px', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                                <HelpCircle size={14} />
                            </div>
                            <div style={{ flex: 1 }}>
                                <div style={{ fontSize: '0.95rem', fontWeight: 500, color: '#111827' }}>{report.examName}</div>
                                <div style={{ fontSize: '0.8rem', color: '#6b7280', marginTop: '0.25rem' }}>Online Assessment</div>
                            </div>
                            <div style={{ textAlign: 'right' }}>
                                <div style={{ fontSize: '0.9rem', color: '#6b7280' }}>{statusStyle(report.passed).text}</div>
                                <div style={{ fontSize: '0.8rem', color: '#9ca3af', marginTop: '0.25rem' }}>Just now</div>
                            </div>
                        </div>
                    </div>

                    {/* Main Report Area */}
                    <div style={{ flex: 1, background: '#fff', borderRadius: '8px', border: '1px solid #e5e7eb', padding: '2rem' }}>

                        <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1.5rem' }}>
                            <div style={{ background: '#fef3c7', color: '#d97706', borderRadius: '50%', width: '36px', height: '36px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                <HelpCircle size={20} />
                            </div>
                            <div>
                                <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 600, color: '#111827' }}>
                                    {report.examName} <span style={{ color: '#9ca3af', fontWeight: 400, fontSize: '1.25rem' }}>- Online Assessment</span>
                                </h2>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginTop: '0.5rem', color: '#6b7280', fontSize: '0.9rem' }}>
                                    <span>{statusStyle(report.passed).text}</span>
                                    <span>•</span>
                                    <span>{new Date(report.dateRun || Date.now()).toLocaleDateString()}</span>
                                </div>
                            </div>
                            <div style={{ flex: 1 }}></div>
                            {report.passed && isEligibleForCertificate(report.examName) && (
                                <button
                                    onClick={handleDownloadCertificate}
                                    style={{
                                        display: 'flex', alignItems: 'center', gap: '0.5rem',
                                        background: 'linear-gradient(135deg, #6366f1, #a855f7)',
                                        color: '#fff', border: 'none', padding: '0.8rem 1.5rem',
                                        borderRadius: '12px', fontWeight: 700, cursor: 'pointer',
                                        boxShadow: '0 4px 15px rgba(99,102,241,0.3)'
                                    }}
                                >
                                    <Award size={18} /> Download Certificate
                                </button>
                            )}
                        </div>

                        <div style={{ marginBottom: '2rem', fontSize: '0.95rem', color: '#374151', display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                            <div><span style={{ color: '#6b7280', marginRight: '0.5rem' }}>Time Spent:</span> {formatTime(timeSpent)}</div>
                            <div><span style={{ color: '#6b7280', marginRight: '0.5rem' }}>Time Allotted:</span> 1 hour</div>
                        </div>

                        {/* Questions List */}
                        <div style={{ borderTop: '1px solid #e5e7eb', paddingTop: '1rem' }}>
                            {report.detailedAnalysis?.codingResults?.map((q, idx) => {
                                const didNotSubmit = !q.userAnswer || q.userAnswer.length < 20;

                                return (
                                    <div key={idx} style={{ padding: '1rem 0', display: 'flex', alignItems: 'flex-start', gap: '1rem', borderBottom: '1px solid #f3f4f6' }}>
                                        <div style={{ marginTop: '0.2rem', color: '#9ca3af' }}>
                                            <FileText size={20} />
                                        </div>
                                        <div style={{ flex: 1 }}>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '0.5rem' }}>
                                                <span style={{ fontWeight: 600, color: '#111827', fontSize: '1rem' }}>{q.questionText || `Question ${idx + 1}`}</span>
                                                <span style={{
                                                    background: '#dcfce7', color: '#166534', fontSize: '0.7rem', fontWeight: 700,
                                                    padding: '0.1rem 0.4rem', borderRadius: '4px'
                                                }}>
                                                    EASY
                                                </span>
                                            </div>

                                            {didNotSubmit ? (
                                                <div style={{ color: '#ef4444', fontSize: '0.9rem' }}>
                                                    Nothing was submitted for this question.
                                                </div>
                                            ) : (
                                                <div style={{ color: q.isCorrect ? '#818cf8' : '#ef4444', fontSize: '0.9rem', fontWeight: 500 }}>
                                                    {q.isCorrect ? 'Accepted' : 'Wrong Answer'}
                                                </div>
                                            )}
                                        </div>
                                        <div style={{ alignSelf: 'center' }}>
                                            <button style={{ color: '#3b82f6', background: 'transparent', border: 'none', fontSize: '0.9rem', cursor: 'pointer' }}>
                                                Details
                                            </button>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>

                    </div>
                </div>
            </div>
        </div>
    );
};

export default MockReport;

import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
    ChevronLeft, Play, Send, Loader2, Brain, CheckCircle,
    AlertCircle, Maximize2, FileText, MessageSquare, History,
    Terminal, Info, ChevronDown, Book, Lock, Tag, Building2, Lightbulb, RotateCcw, Settings, FileCode
} from 'lucide-react';
import Editor from '@monaco-editor/react';
import axios from 'axios';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import Loader from '../components/Loader';

const LANGUAGES = [
    { id: 'javascript', name: 'JavaScript', icon: 'JS', boilerplate: '/**\n * @param {any} input\n * @return {any}\n */\nvar solution = function(input) {\n     \n       \n    };' },
    { id: 'python', name: 'Python3', icon: 'PY', boilerplate: 'class Solution:\n    def solve(self, input: any) -> any:\n        \n        pass' },
    { id: 'java', name: 'Java', icon: 'JV', boilerplate: 'class Solution {\n    public Object solve(Object input) {\n         \n           \n        }\n}' },
    { id: 'cpp', name: 'C++', icon: 'C++', boilerplate: '#include <iostream>\n#include <vector>\n#include <string>\n\nusing namespace std;\n\nclass Solution {\npublic:\n    void solve() {\n         \n           \n    }\n};' },
    { id: 'c', name: 'C', icon: 'C', boilerplate: '#include <stdio.h>\n#include <stdlib.h>\n#include <stdbool.h>\n\nvoid solve() {\n     \n       \n    }' }
];

const ProblemView = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const editorRef = useRef(null);
    const [editorLoaded, setEditorLoaded] = useState(false);
    const [editorError, setEditorError] = useState(false);

    useEffect(() => {
        const timer = setTimeout(() => {
            if (!editorLoaded) {
                setEditorError(true);
            }
        }, 5000);

        // Strict Anti-Cheat Event Interception at Document Level
        const preventCheat = (e) => {
            e.preventDefault();
            e.stopPropagation();
        };

        const preventShortcuts = (e) => {
            if ((e.ctrlKey || e.metaKey) && ['c', 'v', 'x'].includes(e.key.toLowerCase())) {
                e.preventDefault();
                e.stopPropagation();
            }
        };

        // Capture phase listeners to intercept events before Monaco editor handles them
        document.addEventListener('copy', preventCheat, { capture: true });
        document.addEventListener('cut', preventCheat, { capture: true });
        document.addEventListener('paste', preventCheat, { capture: true });
        document.addEventListener('contextmenu', preventCheat, { capture: true });
        document.addEventListener('keydown', preventShortcuts, { capture: true });

        // Global styles to force no selection while assessment is active
        const style = document.createElement('style');
        style.innerHTML = `
            *:not(.monaco-editor):not(.monaco-editor *) {
                -webkit-user-select: none !important;
                -ms-user-select: none !important;
                user-select: none !important;
            }
        `;
        document.head.appendChild(style);

        return () => {
            clearTimeout(timer);
            document.removeEventListener('copy', preventCheat, { capture: true });
            document.removeEventListener('cut', preventCheat, { capture: true });
            document.removeEventListener('paste', preventCheat, { capture: true });
            document.removeEventListener('contextmenu', preventCheat, { capture: true });
            document.removeEventListener('keydown', preventShortcuts, { capture: true });
            if (document.head.contains(style)) {
                document.head.removeChild(style);
            }
        };
    }, [editorLoaded]);

    const [problem, setProblem] = useState(null);
    const [loading, setLoading] = useState(true);
    const [code, setCode] = useState('');
    const [selectedLang, setSelectedLang] = useState(LANGUAGES[0]);
    const [submitting, setSubmitting] = useState(false);
    const [running, setRunning] = useState(false);
    const [result, setResult] = useState(null);
    const [activeLeftTab, setActiveLeftTab] = useState('Description');
    const [activeBottomTab, setActiveBottomTab] = useState('Testcase');
    const [activeTestCaseTab, setActiveTestCaseTab] = useState(0);
    const [showLangMenu, setShowLangMenu] = useState(false);
    const [showHints, setShowHints] = useState(false);
    const [showTags, setShowTags] = useState(false);

    const getCodingQuestion = () => {
        if (!problem) return null;

        // If it's a Topic
        if (problem.content) {
            return {
                ...problem.content,
                title: problem.title,
                isTopic: true,
                _id: problem._id
            };
        }

        // If it's an Exam
        const codingQ = problem.questions?.find(q => q.type === 'coding') || problem.questions?.[0];
        return codingQ ? { ...codingQ, isExam: true } : null;
    };

    const q = getCodingQuestion();

    useEffect(() => {
        const fetchProblem = async () => {
            try {
                const res = await axios.get(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/users/problems/${id}`, {
                    headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
                });

                const data = res.data;
                setProblem(data);
                setActiveTestCaseTab(0);

                // Normalize for initial code load
                let codingQ;
                if (data.content) {
                    codingQ = data.content;
                } else {
                    codingQ = data.questions?.find(q => q.type === 'coding') || data.questions?.[0];
                }

                if (codingQ) {
                    const jsCode = codingQ.starterCode || LANGUAGES.find(l => l.id === 'javascript').boilerplate;

                    // 1. Check if problem has language-specific starter code in DB
                    if (codingQ?.starterCodes?.[selectedLang.id]) {
                        setCode(codingQ.starterCodes[selectedLang.id]);
                        return;
                    }

                    // 2. Special case for JavaScript (fallback to starterCode if no starterCodes object)
                    if (selectedLang.id === 'javascript') {
                        setCode(jsCode);
                        return;
                    }

                    // 3. Fallback: Smart Boilerplate Gen
                    const funcMatch = jsCode.match(/var\s+(\w+)\s*=\s*function\s*\(([^)]*)\)/);
                    const funcName = funcMatch ? funcMatch[1] : 'solution';
                    const params = funcMatch ? funcMatch[2].trim() : 'input';

                    let smartCode = selectedLang.boilerplate;

                    if (selectedLang.id === 'python') {
                        smartCode = `class Solution:\n    def ${funcName}(self, ${params}):\n        \n        pass`;
                    } else if (selectedLang.id === 'cpp') {
                        smartCode = `// Update Return Type as needed\nvoid ${funcName}(${params.split(',').map(p => 'auto ' + p.trim()).join(', ')}) {\n     \n       \n    }`;
                    } else if (selectedLang.id === 'java') {
                        smartCode = `class Solution {\n    public Object ${funcName}(${params.split(',').map(p => 'Object ' + p.trim()).join(', ')}) {\n         \n           \n        }\n}`;
                    } else if (selectedLang.id === 'c') {
                        smartCode = `// Update Return Type and types as needed\nvoid ${funcName}(${params.split(',').map(p => 'void* ' + p.trim()).join(', ')}) {\n     \n       \n    }`;
                    }

                    setCode(smartCode);
                }
            } catch (err) {
                console.error("Error fetching problem:", err);
            } finally {
                setLoading(false);
            }
        };
        fetchProblem();
    }, [id]);

    const handleCodeChange = (val) => {
        setCode(val);
    };

    const handleKeyDown = (e) => {
        // Monaco handles Tab automatically
    };

    const handleLangChange = (lang) => {
        setSelectedLang(lang);
        setShowLangMenu(false);

        let codingQ;
        if (problem.content) {
            codingQ = problem.content;
        } else {
            codingQ = problem.questions?.find(q => q.type === 'coding') || problem.questions?.[0];
        }

        console.log("Language change to:", lang.id, "CodingQ available:", !!codingQ);
        if (codingQ) console.log("StarterCodes present:", Object.keys(codingQ.starterCodes || {}).length > 0);

        const jsCode = codingQ?.starterCode || LANGUAGES.find(l => l.id === 'javascript').boilerplate;

        // 1. Try to get problem-specific starter code from database
        if (codingQ?.starterCodes && codingQ.starterCodes[lang.id]) {
            console.log("Loading starter code from DB for:", lang.id);
            setCode(codingQ.starterCodes[lang.id]);
            return;
        }

        // 2. Logic for JavaScript (Original/Seeded)
        if (lang.id === 'javascript') {
            setCode(jsCode);
            return;
        }

        // --- 3. Smart Boilerplate Generation Logic (Fallback) ---
        const funcMatch = jsCode.match(/var\s+(\w+)\s*=\s*function\s*\(([^)]*)\)/);
        const funcName = funcMatch ? funcMatch[1] : 'solution';
        const params = funcMatch ? funcMatch[2].trim() : 'input';

        let smartCode = lang.boilerplate;

        if (lang.id === 'python') {
            smartCode = `class Solution:\n    def ${funcName}(self, ${params}):\n        \n        pass`;
        } else if (lang.id === 'cpp') {
            smartCode = `// Update Return Type as needed\nvoid ${funcName}(${params.split(',').map(p => 'auto ' + p.trim()).join(', ')}) {\n     \n       \n    }`;
        } else if (lang.id === 'java') {
            smartCode = `class Solution {\n    public Object ${funcName}(${params.split(',').map(p => 'Object ' + p.trim()).join(', ')}) {\n         \n           \n        }\n}`;
        } else if (lang.id === 'c') {
            smartCode = `// Update Return Type and types as needed\nvoid ${funcName}(${params.split(',').map(p => 'void* ' + p.trim()).join(', ')}) {\n     \n       \n    }`;
        }

        setCode(smartCode);
    };

    if (loading) return <Loader text="Synapsing Challenge Architectures..." />;

    if (!problem) return <div style={{ color: '#fff', textAlign: 'center', padding: '4rem' }}>Problem not found.</div>;

    const handleSubmit = async (isRun = false) => {
        if (isRun) setRunning(true);
        else setSubmitting(true);

        setActiveBottomTab('Test Result');
        setResult(null);

        try {
            document.documentElement.requestFullscreen().catch(err => {
                console.log(`Fullscreen error: ${err.message}`);
            });
        } catch (e) {
            console.error("Fullscreen API not supported.", e);
        }

        // HTML/Web Detection for Local Preview
        const trimmedCode = code.trim().toLowerCase();
        const isHTML = trimmedCode.startsWith('<!doctype') || trimmedCode.startsWith('<html') || trimmedCode.startsWith('<div') || trimmedCode.startsWith('<p') || trimmedCode.startsWith('<script') || trimmedCode.startsWith('<style');

        if (isRun && isHTML) {
            setResult({
                status: 'Success',
                message: 'HTML Preview',
                isPreview: true,
                html: code,
                aiFeedback: 'Web content rendered in preview mode.'
            });
            setRunning(false);
            return;
        }

        try {
            console.log(`🚀 Sending submission to: ${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/users/submit-exam`);
            console.log(`📦 Payload:`, {
                examName: problem.title,
                language: selectedLang.id,
                isRun
            });

            const res = await axios.post(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/users/submit-exam`, {
                examName: problem.title,
                language: selectedLang.id,
                answers: { 0: code },
                isRun
            }, {
                headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
            });
            setResult(res.data.result);

            if (!isRun && res.data.result?.passed) {
                setTimeout(() => {
                    navigate('/problems');
                }, 1000);
            }
        } catch (err) {
            console.error("❌ Submission failed:", err);
            if (err.response) {
                console.error("📊 Status:", err.response.status);
                console.error("📄 Data:", err.response.data);
            }
            alert(`Execution failed (${err.response?.status || 'Network Error'}). Please try again.`);
        } finally {
            setSubmitting(false);
            setRunning(false);
        }
    };

    const leftTabs = [
        { id: 'Description', icon: <FileText size={16} /> },
        { id: 'Editorial', icon: <Book size={16} /> },
        { id: 'Solutions', icon: <MessageSquare size={16} /> },
        { id: 'Submissions', icon: <History size={16} /> }
    ];

    return (
        <div
            className="problem-view-layout"
            style={{
                height: 'calc(100vh - 56px)',
                display: 'flex',
                flexDirection: 'column',
                background: '#0a0a0a',
                color: '#fff',
                fontFamily: 'Inter, sans-serif',
                userSelect: 'none',
                WebkitUserSelect: 'none',
                msUserSelect: 'none',
                MozUserSelect: 'none'
            }}
            onCopy={(e) => e.preventDefault()}
            onCut={(e) => e.preventDefault()}
            onPaste={(e) => e.preventDefault()}
        >
            {/* Header Navigation */}
            <div style={{
                height: '45px',
                borderBottom: '1px solid rgba(255,255,255,0.05)',
                display: 'flex',
                alignItems: 'center',
                padding: '0 1rem',
                justifyContent: 'space-between',
                background: '#1a1a1a',
                flexShrink: 0
            }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                    <button onClick={() => navigate('/problems')} style={{ background: 'transparent', border: 'none', color: 'rgba(255,255,255,0.5)', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                        <ChevronLeft size={18} />
                        <span style={{ fontSize: '0.85rem', fontWeight: 500 }}>Problem List</span>
                    </button>
                    <div style={{ width: '1px', height: '16px', background: 'rgba(255,255,255,0.1)' }}></div>
                    <span style={{ fontSize: '0.9rem', fontWeight: 600 }}>{problem.title}</span>
                </div>

                <div style={{ display: 'flex', gap: '0.5rem' }}>
                    <button style={{ background: 'transparent', border: 'none', color: 'rgba(255,255,255,0.4)', cursor: 'pointer', padding: '0.5rem' }}>
                        <Info size={18} />
                    </button>
                </div>
            </div>

            {/* Main Content Area */}
            <div style={{ flex: 1, display: 'flex', overflow: 'hidden', padding: '0.5rem', gap: '0.5rem' }}>
                {/* Left Side: Information & Description */}
                <div style={{ flex: 1, display: 'flex', flexDirection: 'column', background: '#1a1a1a', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.05)', overflow: 'hidden' }}>
                    {/* Left Tabs */}
                    <div style={{ display: 'flex', background: '#262626', borderBottom: '1px solid rgba(255,255,255,0.05)', padding: '2px 8px' }}>
                        {leftTabs.map(tab => (
                            <button
                                key={tab.id}
                                onClick={() => setActiveLeftTab(tab.id)}
                                style={{
                                    display: 'flex',
                                    alignItems: 'center',
                                    gap: '0.5rem',
                                    padding: '0.6rem 1rem',
                                    background: activeLeftTab === tab.id ? '#1a1a1a' : 'transparent',
                                    color: activeLeftTab === tab.id ? '#fff' : 'rgba(255,255,255,0.4)',
                                    border: 'none',
                                    borderBottom: activeLeftTab === tab.id ? '2px solid #fff' : 'none',
                                    fontSize: '0.78rem',
                                    fontWeight: 500,
                                    cursor: 'pointer',
                                    transition: '0.2s'
                                }}
                            >
                                {tab.icon}
                                {tab.id}
                            </button>
                        ))}
                    </div>

                    <div style={{ flex: 1, overflowY: 'auto', padding: '2rem' }}>
                        {activeLeftTab === 'Description' && (
                            <div className="problem-content">
                                <h1 style={{ fontSize: '1.5rem', marginBottom: '1.25rem', fontWeight: 700 }}>{problem.title}</h1>

                                <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.75rem', marginBottom: '1.5rem' }}>
                                    <span style={{
                                        padding: '0.25rem 0.75rem',
                                        borderRadius: '100px',
                                        background: q?.difficulty === 'Easy' ? 'rgba(129, 140, 248, 0.1)' : q?.difficulty === 'Hard' ? 'rgba(239,68,68,0.1)' : 'rgba(245,158,11,0.1)',
                                        color: q?.difficulty === 'Easy' ? '#818cf8' : q?.difficulty === 'Hard' ? '#ef4444' : '#f59e0b',
                                        fontSize: '0.72rem',
                                        fontWeight: 700
                                    }}>
                                        {q?.difficulty || 'Medium'}
                                    </span>

                                    <button
                                        onClick={() => setShowTags(!showTags)}
                                        style={{
                                            display: 'flex',
                                            alignItems: 'center',
                                            gap: '0.35rem',
                                            background: showTags ? 'rgba(255,255,255,0.1)' : 'rgba(255,255,255,0.05)',
                                            border: 'none',
                                            borderRadius: '100px',
                                            padding: '0.25rem 0.75rem',
                                            color: showTags ? '#fff' : 'rgba(255,255,255,0.6)',
                                            fontSize: '0.7rem',
                                            cursor: 'pointer',
                                            transition: '0.2s'
                                        }}
                                    >
                                        <Tag size={12} /> Topics {q?.tags?.length > 0 && `(${q.tags.length})`}
                                    </button>

                                    {showTags && q?.tags?.length > 0 && (
                                        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.5rem', width: '100%', marginTop: '0.5rem', animation: 'fadeIn 0.2s ease-out' }}>
                                            {q.tags.map((tag, idx) => (
                                                <span key={idx} style={{
                                                    padding: '0.2rem 0.6rem',
                                                    borderRadius: '100px',
                                                    background: 'rgba(255,255,255,0.08)',
                                                    color: 'rgba(255,255,255,0.8)',
                                                    fontSize: '0.65rem',
                                                    fontWeight: 600
                                                }}>
                                                    {tag}
                                                </span>
                                            ))}
                                        </div>
                                    )}

                                    <button style={{ display: 'flex', alignItems: 'center', gap: '0.35rem', background: 'rgba(255,255,255,0.05)', border: 'none', borderRadius: '100px', padding: '0.25rem 0.75rem', color: 'rgba(255,255,255,0.6)', fontSize: '0.7rem', cursor: 'pointer' }}>
                                        <Building2 size={12} /> Companies
                                    </button>

                                    <button
                                        onClick={() => setShowHints(!showHints)}
                                        style={{
                                            display: 'flex',
                                            alignItems: 'center',
                                            gap: '0.35rem',
                                            background: showHints ? 'rgba(245,158,11,0.2)' : 'rgba(255,255,255,0.05)',
                                            border: 'none',
                                            borderRadius: '100px',
                                            padding: '0.25rem 0.75rem',
                                            color: showHints ? '#f59e0b' : 'rgba(255,255,255,0.6)',
                                            fontSize: '0.7rem',
                                            cursor: 'pointer',
                                            transition: '0.2s'
                                        }}
                                    >
                                        <Lightbulb size={12} /> Hint {q?.hints?.length > 0 && `(${q.hints.length})`}
                                    </button>
                                </div>

                                <div className="markdown-body" style={{ color: 'rgba(255,255,255,0.9)', fontSize: '1rem', lineHeight: '1.7' }}>
                                    <ReactMarkdown remarkPlugins={[remarkGfm]}>
                                        {q?.questionText || q?.description || "No description available."}
                                    </ReactMarkdown>
                                </div>

                                {q?.constraints && (
                                    <div style={{ marginTop: '2.5rem' }}>
                                        <h3 style={{ fontSize: '1rem', fontWeight: 700, marginBottom: '0.75rem', color: '#fff' }}>Constraints:</h3>
                                        <div className="markdown-body" style={{ fontSize: '0.9rem', color: 'rgba(255,255,255,0.7)' }}>
                                            <ReactMarkdown remarkPlugins={[remarkGfm]}>
                                                {q.constraints}
                                            </ReactMarkdown>
                                        </div>
                                    </div>
                                )}

                                {showHints && q?.hints?.length > 0 && (
                                    <div style={{ marginTop: '2rem', display: 'flex', flexDirection: 'column', gap: '1rem', animation: 'fadeIn 0.3s ease-out' }}>
                                        {q.hints.map((hint, idx) => (
                                            <div key={idx} style={{
                                                background: 'rgba(255,255,255,0.03)',
                                                border: '1px solid rgba(255,255,255,0.05)',
                                                borderRadius: '8px',
                                                overflow: 'hidden'
                                            }}>
                                                <div style={{
                                                    padding: '0.6rem 1rem',
                                                    background: 'rgba(255,255,255,0.02)',
                                                    borderBottom: '1px solid rgba(255,255,255,0.05)',
                                                    fontSize: '0.75rem',
                                                    fontWeight: 800,
                                                    color: 'rgba(255,255,255,0.4)',
                                                    textTransform: 'uppercase'
                                                }}>
                                                    Hint {idx + 1}
                                                </div>
                                                <div style={{ padding: '1rem', color: 'rgba(255,255,255,0.7)', fontSize: '0.9rem', lineHeight: '1.6' }}>
                                                    {hint}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                )}

                                <div style={{ marginTop: '3rem', borderTop: '1px solid rgba(255,255,255,0.05)', paddingTop: '1.5rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                    <div style={{ color: 'rgba(255,255,255,0.4)', fontSize: '0.8rem' }}>
                                        Seen this question in a real interview?
                                    </div>
                                    <div style={{ display: 'flex', gap: '0.5rem' }}>
                                        <button style={{ background: 'rgba(255,255,255,0.05)', border: 'none', borderRadius: '6px', padding: '0.25rem 0.75rem', color: '#fff', fontSize: '0.75rem', cursor: 'pointer' }}>Yes</button>
                                        <button style={{ background: 'rgba(255,255,255,0.05)', border: 'none', borderRadius: '6px', padding: '0.25rem 0.75rem', color: '#fff', fontSize: '0.75rem', cursor: 'pointer' }}>No</button>
                                    </div>
                                </div>
                            </div>
                        )}
                        {activeLeftTab === 'Editorial' && (
                            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '100%', color: 'rgba(255,255,255,0.3)' }}>
                                <Lock size={48} style={{ marginBottom: '1.5rem', opacity: 0.1 }} />
                                <h3 style={{ color: '#fff', marginBottom: '0.5rem' }}>Editorial Locked</h3>
                                <p style={{ fontSize: '0.9rem', marginBottom: '1.5rem', textAlign: 'center' }}>Subscribe to Premium to unlock full editorial and optimal solutions.</p>
                                <button style={{ background: '#f59e0b', color: '#000', border: 'none', borderRadius: '8px', padding: '0.7rem 2rem', fontWeight: 800, fontSize: '0.9rem', cursor: 'pointer' }}>Go Premium</button>
                            </div>
                        )}
                        {activeLeftTab === 'Solutions' && (
                            <div style={{ padding: '2rem', textAlign: 'center', color: 'rgba(255,255,255,0.3)' }}>
                                <MessageSquare size={48} style={{ marginBottom: '1rem', opacity: 0.1 }} />
                                <p>No community solutions yet. Be the first to share!</p>
                            </div>
                        )}
                        {activeLeftTab === 'Submissions' && (
                            <div style={{ padding: '2rem', textAlign: 'center', color: 'rgba(255,255,255,0.3)' }}>
