                        </div>
                    </div>
                </div>
            )}

            {/* All History Modal */}
            {showAllExams && (
                <div style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(0,0,0,0.8)', backdropFilter: 'blur(10px)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '2rem' }}>
                    <div style={{ background: '#0a0a0a', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '40px', width: '100%', maxWidth: '800px', maxHeight: '80vh', display: 'flex', flexDirection: 'column' }}>
                        <div style={{ padding: '2.5rem', borderBottom: '1px solid rgba(255,255,255,0.05)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                            <h2 style={{ fontSize: '1.5rem', fontWeight: 800, color: '#fff', margin: 0 }}>Submission History</h2>
                            <button onClick={() => setShowAllExams(false)} style={{ background: 'transparent', border: 'none', color: '#fff', cursor: 'pointer' }}><X size={24} /></button>
                        </div>
                        <div style={{ flex: 1, overflowY: 'auto', padding: '2.5rem', display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                            {[...userData.examScores].reverse().map((exam, i) => (
                                <div key={i} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '1.5rem', borderRadius: '24px', background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.03)' }}>
                                    <div>
                                        <div style={{ fontWeight: 800, color: '#fff', fontSize: '1.1rem', marginBottom: '0.3rem' }}>{exam.examName}</div>
                                        <div style={{ fontSize: '0.85rem', opacity: 0.5 }}>{new Date(exam.dateRun).toLocaleDateString()} • {exam.language || 'Code'}</div>
                                    </div>
                                    <div style={{ textAlign: 'right' }}>
                                        <div style={{ color: exam.passed ? '#818cf8' : '#ef4444', fontWeight: 900, fontSize: '1rem' }}>{exam.passed ? 'ACCEPTED' : 'REJECTED'}</div>
                                        <div style={{ fontSize: '0.9rem', opacity: 0.6 }}>{exam.score} / {exam.totalMarks} points</div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

const SidebarItem = ({ icon, text, link }) => (
    <div style={{ display: 'flex', alignItems: 'center', gap: '0.8rem', color: 'rgba(255,255,255,0.6)', fontSize: '0.9rem' }}>
        <span style={{ color: '#818cf8' }}>{icon}</span>
        {link ? <a href={link} target="_blank" rel="noreferrer" style={{ color: 'inherit', textDecoration: 'none' }}>{text || 'N/A'}</a> : <span>{text || 'N/A'}</span>}
    </div>
);

const EditField = ({ label, value, onChange, type = 'text', options = [] }) => (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '0.6rem' }}>
        <label style={{ fontSize: '0.85rem', fontWeight: 700, opacity: 0.4, textTransform: 'uppercase', letterSpacing: '1px' }}>{label}</label>
        {type === 'select' ? (
            <select value={value} onChange={e => onChange(e.target.value)} style={{ padding: '1.2rem', background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '16px', color: '#fff', fontSize: '1rem', outline: 'none' }}>
                {options.map(o => <option key={o} value={o}>{o}</option>)}
            </select>
        ) : type === 'textarea' ? (
            <textarea value={value} onChange={e => onChange(e.target.value)} style={{ padding: '1.2rem', background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '16px', color: '#fff', fontSize: '1rem', outline: 'none', minHeight: '120px', resize: 'vertical' }} />
        ) : (
            <input type={type} value={value} onChange={e => onChange(e.target.value)} style={{ padding: '1.2rem', background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '16px', color: '#fff', fontSize: '1rem', outline: 'none' }} />
        )}
    </div>
);

const getSocialIcon = (name) => {
    switch (name) {
        case 'github': return <Github size={18} />;
        case 'linkedin': return <Linkedin size={18} />;
        case 'twitter': return <Twitter size={18} />;
        case 'leetcode': return <Code size={18} />;
        default: return <Globe size={18} />;
    }
};

export default Profile;

import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { User, Mail, Lock, BookOpen, Briefcase, Loader2, ArrowRight, CheckCircle, Sparkles } from 'lucide-react';
import Loader from '../components/Loader';
import { GoogleLogin } from '@react-oauth/google';
import './Auth.css';

const allSkills = [
    "JavaScript", "Python", "React", "Node.js", "Docker", "AWS", "ML/AI", "SQL", "Java", "CS Fundamentals"
];

const Register = () => {
    const [formData, setFormData] = useState({
        name: '', email: '', password: '', education: '', experience: '', skills: []
    });
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [skillSearch, setSkillSearch] = useState('');
    const navigate = useNavigate();

    const handleChange = (e) => setFormData({ ...formData, [e.target.name]: e.target.value });

    const toggleSkill = (skill) => {
        if (formData.skills.includes(skill)) {
            setFormData({ ...formData, skills: formData.skills.filter(s => s !== skill) });
        } else if (formData.skills.length < 5) {
            setFormData({ ...formData, skills: [...formData.skills, skill] });
        }
    };

    const handleRegister = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');
        try {
            const res = await fetch(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/auth/register`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(formData)
            });
            const data = await res.json();
            if (res.ok) {
                localStorage.setItem('token', data.token);
                localStorage.setItem('userRole', data.role);
                navigate('/onboarding');
            } else {
                setError(data.message || 'Initialization Failed');
            }
        } catch (err) {
            setError('System Fault During Handshake');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="auth-page">
            <div className="auth-side-visual">
                <div className="auth-visual-pill">
                    <Sparkles size={14} />
                    <span>Join the 1% Factor</span>
                </div>
                <h1 className="auth-visual-title">
                    Build Your <br />
                    <span className="highlight">Architect</span> Profile.
                </h1>
                <p className="auth-visual-subtitle">
                    Transform your career trajectory with elite assessments and industry-first credentials.
                </p>

                <div className="auth-feature-grid">
                    <div className="auth-feature-card">
                        <CheckCircle size={24} color="#818cf8" />
                        <h4>Verified Badges</h4>
                        <p>Credentials that top recruiters actually trust.</p>
                    </div>
                    <div className="auth-feature-card">
                        <Lock size={24} color="#6366f1" />
                        <h4>Secured Sync</h4>
                        <p>Your progress, synced across every developer node.</p>
                    </div>
                </div>
            </div>

            <div className="auth-side-form" style={{ overflowY: 'auto' }}>
                <div className="auth-form-card" style={{ margin: '2rem 0', maxWidth: '480px' }}>
                    <header className="auth-header">
                        <img src="/logo.png" alt="Dev2Dev" className="auth-logo" />
                        <h2>Identity Genesis</h2>
                        <p>Initialize your global developer profile</p>
                    </header>

                    {error && (
                        <div style={{ background: 'rgba(239, 68, 68, 0.1)', border: '1px solid rgba(239, 68, 68, 0.2)', color: '#ef4444', padding: '0.8rem', borderRadius: '12px', fontSize: '0.85rem', textAlign: 'center', marginBottom: '1.5rem', fontWeight: 600 }}>
                            {error}
                        </div>
                    )}

                    <form onSubmit={handleRegister}>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.8rem' }}>
                            <div className="auth-field">
                                <label className="auth-label">Full Name</label>
                                <div className="auth-input-wrapper" style={{ height: '54px' }}>
                                    <User size={16} color="rgba(255,255,255,0.2)" />
                                    <input type="text" name="name" className="auth-input" placeholder="Elite User" value={formData.name} onChange={handleChange} required />
                                </div>
                            </div>
                            <div className="auth-field">
                                <label className="auth-label">Vault ID</label>
                                <div className="auth-input-wrapper" style={{ height: '54px' }}>
                                    <Mail size={16} color="rgba(255,255,255,0.2)" />
                                    <input type="email" name="email" className="auth-input" placeholder="id@dev.ai" value={formData.email} onChange={handleChange} required />
                                </div>
                            </div>
                        </div>

                        <div className="auth-field">
                            <label className="auth-label">Universal Passkey</label>
                            <div className="auth-input-wrapper" style={{ height: '54px' }}>
                                <Lock size={16} color="rgba(255,255,255,0.2)" />
                                <input type="password" name="password" className="auth-input" placeholder="••••••••" value={formData.password} onChange={handleChange} required />
                            </div>
                        </div>

                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.8rem' }}>
                            <div className="auth-field">
                                <label className="auth-label">Education</label>
                                <div className="auth-input-wrapper" style={{ height: '54px' }}>
                                    <select name="education" className="auth-input" value={formData.education} onChange={handleChange} required style={{ appearance: 'none', background: 'transparent' }}>
                                        <option value="" disabled style={{ background: '#000' }}>Select</option>
                                        <option value="Bachelors" style={{ background: '#000' }}>Bachelors</option>
                                        <option value="Masters" style={{ background: '#000' }}>Masters</option>
                                        <option value="Self-Taught" style={{ background: '#000' }}>Self-Taught</option>
                                    </select>
                                </div>
                            </div>
                            <div className="auth-field">
                                <label className="auth-label">Experience Tier</label>
                                <div className="auth-input-wrapper" style={{ height: '54px' }}>
                                    <select name="experience" className="auth-input" value={formData.experience} onChange={handleChange} required style={{ appearance: 'none', background: 'transparent' }}>
                                        <option value="" disabled style={{ background: '#000' }}>Tier</option>
                                        <option value="Fresher" style={{ background: '#000' }}>Fresher</option>
                                        <option value="1-3 Years" style={{ background: '#000' }}>Junior</option>
                                        <option value="3-5 Years" style={{ background: '#000' }}>Senior</option>
                                    </select>
                                </div>
                            </div>
                        </div>

                        <div className="auth-field">
                            <label className="auth-label">Stack Core (Max 5)</label>
                            <div style={{ position: 'relative' }}>
                                <div className="auth-input-wrapper" style={{ height: 'auto', minHeight: '54px', padding: '0.6rem 1rem', flexWrap: 'wrap', gap: '0.5rem' }}>
                                    {formData.skills.map(skill => (
                                        <span key={skill} onClick={() => toggleSkill(skill)} className="skill-tag" style={{ padding: '0.3rem 0.8rem', fontSize: '0.75rem' }}>
                                            {skill}
                                        </span>
                                    ))}
                                    <input
                                        type="text"
                                        placeholder={formData.skills.length === 0 ? "Identify skills..." : ""}
                                        className="auth-input"
                                        style={{ height: '28px', minWidth: '100px', fontSize: '0.85rem' }}
                                        value={skillSearch}
                                        onChange={(e) => setSkillSearch(e.target.value)}
                                    />
                                </div>
                            </div>
                        </div>

                        <button type="submit" className="auth-btn-primary" style={{ height: '54px' }} disabled={loading}>
                            {loading ? <Loader inline={true} text="Initializing..." /> : <>Initialize Journey <ArrowRight size={20} /></>}
                        </button>
                    </form>

                    <p className="auth-footer">
                        Already in? <Link to="/login" className="auth-link">Authenticate</Link>
                    </p>
                </div>
            </div>
        </div>
    );
};

export default Register;

import React, { useState } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { Lock, Loader2, ArrowRight, ShieldCheck, Zap } from 'lucide-react';
import Loader from '../components/Loader';
import './Auth.css';

const ResetPassword = () => {
    const { token } = useParams();
    const navigate = useNavigate();
    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');
    const [error, setError] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (password !== confirmPassword) {
            setError('Mismatch in security keys');
            return;
        }

        setLoading(true);
        setError('');

        try {
            const res = await fetch(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/auth/reset-password/${token}`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ password })
            });
            const data = await res.json();
            if (res.ok) {
                setMessage('Security system updated! Redirecting...');
                setTimeout(() => navigate('/login'), 2000);
            } else {
                setError(data.message || 'Invalid or expired restoration token');
            }
        } catch (err) {
            setError('System synchronization failed');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="auth-page">
            <div className="auth-side-visual">
                <div className="auth-visual-pill">
                    <Zap size={14} />
                    <span>System Override</span>
                </div>
                <h1 className="auth-visual-title">
                    Establish New <br />
                    <span className="highlight">Parameters.</span>
                </h1>
                <p className="auth-visual-subtitle">
                    Create a new, highly secure access key for your Dev2Dev ecosystem profile.
                </p>

                <div className="auth-feature-grid">
                    <div className="auth-feature-card">
                        <ShieldCheck size={24} color="#6366f1" />
                        <h4>Vault Secured</h4>
                        <p>Your data integrity is maintained through key rotation.</p>
                    </div>
                </div>
            </div>

            <div className="auth-side-form">
                <div className="auth-form-card">
                    <header className="auth-header">
                        <img src="/logo.png" alt="Dev2Dev" className="auth-logo" />
                        <h2>Reset Vault</h2>
                        <p>Establish a specialized new access key</p>
                    </header>

                    {message && (
                        <div style={{ background: 'rgba(129, 140, 248, 0.1)', border: '1px solid rgba(129, 140, 248, 0.2)', color: '#818cf8', padding: '1rem', borderRadius: '18px', marginBottom: '2.5rem', textAlign: 'center', fontWeight: 600 }}>
                            {message}
                        </div>
                    )}

                    {error && <div className="auth-error-badge">{error}</div>}

                    <form onSubmit={handleSubmit}>
                        <div className="auth-field">
                            <label className="auth-label">New Access Key</label>
                            <div className="auth-input-wrapper">
                                <Lock size={20} color="rgba(255,255,255,0.2)" style={{ marginRight: '1rem' }} />
                                <input
                                    type="password"
                                    className="auth-input"
                                    placeholder="••••••••"
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    required
                                />
                            </div>
                        </div>

                        <div className="auth-field">
                            <label className="auth-label">Verify New Key</label>
                            <div className="auth-input-wrapper">
                                <Lock size={20} color="rgba(255,255,255,0.2)" style={{ marginRight: '1rem' }} />
                                <input
                                    type="password"
                                    className="auth-input"
                                    placeholder="••••••••"
                                    value={confirmPassword}
                                    onChange={(e) => setConfirmPassword(e.target.value)}
                                    required
                                />
                            </div>
                        </div>

                        <button type="submit" className="auth-btn-primary" disabled={loading}>
                            {loading ? <Loader text="Updating security parameters..." /> : <>Update Vault <ArrowRight size={20} /></>}
                        </button>
                    </form>
                </div>
            </div>
        </div>
    );
};

export default ResetPassword;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Play, CheckCircle, Clock, ChevronLeft, Lock, BookOpen, Share2, Award, Zap, Loader2 } from 'lucide-react';
import axios from 'axios';
import Loader from '../components/Loader';
import { generateCertificate, isEligibleForCertificate } from '../utils/certificateGenerator';

const TutorialPlayer = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const [tutorial, setTutorial] = useState(null);
    const [activeVideo, setActiveVideo] = useState(null);
    const [isUnlocked, setIsUnlocked] = useState(false);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchTutorial = async () => {
            try {
                const token = localStorage.getItem('token');
                const res = await axios.get(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/tutorials/${id}`, {
                    headers: { Authorization: `Bearer ${token}` }
                });
                setTutorial(res.data);
                if (res.data.lessons.length > 0) {
                    setActiveVideo(res.data.lessons[0]);
                }

                const userString = localStorage.getItem('user');
                let unlockedList = [];
                if (userString) {
                    try {
                        const user = JSON.parse(userString);
                        unlockedList = user.unlockedTutorials || [];
                    } catch (e) { }
                }
                setIsUnlocked(unlockedList.includes(res.data._id));

                setLoading(false);
            } catch (err) {
                console.error('Error fetching tutorial:', err);
                setLoading(false);
            }
        };
        fetchTutorial();
    }, [id]);

    const handleCheckout = async () => {
        try {
            const token = localStorage.getItem('token');
            const { data: order } = await axios.post(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/payment/create-order`,
                { type: 'tutorial', tutorialId: tutorial._id, amount: tutorial.price },
                { headers: { Authorization: `Bearer ${token}` } }
            );

            const options = {
                key: import.meta.env.VITE_RAZORPAY_KEY_ID,
                amount: order.amount,
                currency: order.currency,
                name: "dev to dev",
                description: `Unlock ${tutorial.title}`,
                order_id: order.id,
                handler: async function (response) {
                    try {
                        const verifyRes = await axios.post(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/payment/verify-payment`, {
                            razorpay_order_id: response.razorpay_order_id,
                            razorpay_payment_id: response.razorpay_payment_id,
                            razorpay_signature: response.razorpay_signature,
                            type: 'tutorial',
                            tutorialId: tutorial._id
                        }, { headers: { Authorization: `Bearer ${token}` } });

                        if (verifyRes.data.unlockedTutorials && verifyRes.data.unlockedTutorials.includes(tutorial._id)) {
                            setIsUnlocked(true);

                            // Update local storage
                            const userString = localStorage.getItem('user');
                            if (userString) {
                                const user = JSON.parse(userString);
                                user.unlockedTutorials = verifyRes.data.unlockedTutorials;
                                localStorage.setItem('user', JSON.stringify(user));
                            }
                            alert("Tutorial Unlocked successfully!");
                        }
                    } catch (error) {
                        console.error("Payment verification failed", error);
                        alert("Payment verification failed.");
                    }
                },
                theme: {
                    color: "#6366f1"
                }
            };
            const rzp1 = new window.Razorpay(options);
            rzp1.on('payment.failed', function (response) {
                alert("Payment Failed: " + response.error.description);
            });
            rzp1.open();
        } catch (error) {
            console.error("Error initiating checkout:", error);
            alert("Could not initiate checkout. Please try again.");
        }
    };

    const handleDownloadCertificate = () => {
        if (!tutorial) return;

        const userStr = localStorage.getItem('user');
        const user = userStr ? JSON.parse(userStr) : { name: 'DevElevator' };

        generateCertificate(user, {
            examName: tutorial.title,
            score: 'Passed',
            totalMarks: 'Complete',
            dateRun: new Date()
        }, 'TUTORIAL');
    };

    if (loading) return <Loader text="Loading tutorial content..." />;

    if (!tutorial) return (
        <div style={{ minHeight: '100vh', background: '#0a0a0a', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', color: '#fff' }}>
            <h2>Tutorial not found</h2>
            <button onClick={() => navigate('/tutorials')} style={{ marginTop: '1rem', background: '#6366f1', border: 'none', padding: '0.5rem 1rem', borderRadius: '8px', color: '#fff', cursor: 'pointer' }}>Go Back</button>
        </div>
    );

    return (
        <div style={{ minHeight: 'calc(100vh - 56px)', background: '#0a0a0a', color: '#fff', fontFamily: 'Inter, sans-serif' }}>
            {/* Header / Breadcrumbs area */}
            <div style={{
                background: 'linear-gradient(135deg, rgba(99, 102, 241, 0.1) 0%, rgba(10, 10, 10, 1) 100%)',
                padding: '1.5rem 3rem',
                borderBottom: '1px solid rgba(255,255,255,0.05)',
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center'
            }}>
                <div>
                    <button
                        onClick={() => navigate('/tutorials')}
                        style={{ background: 'none', border: 'none', color: '#6366f1', display: 'flex', alignItems: 'center', gap: '0.5rem', cursor: 'pointer', fontSize: '0.9rem', marginBottom: '0.75rem', padding: 0 }}
                    >
                        <ChevronLeft size={16} /> Back to Tutorials
                    </button>
                    <h1 style={{ fontSize: '1.8rem', fontWeight: 800, marginBottom: '0.5rem', display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                        <Zap size={24} color="#6366f1" /> {tutorial.title}
                    </h1>
                </div>
                <div style={{ textAlign: 'right' }}>
                    <div style={{ fontSize: '0.75rem', color: 'rgba(255,255,255,0.4)', marginBottom: '0.25rem' }}>PLAYING</div>
                    <div style={{ fontSize: '0.9rem', fontWeight: 700, color: '#6366f1' }}>Lesson {tutorial.lessons.findIndex(l => l._id === activeVideo?._id) + 1} of {tutorial.lessons.length}</div>
                </div>
            </div>

            <div style={{ display: 'flex', height: 'auto' }}>
                {/* Main Content Area */}
                <main style={{ flex: 1, padding: '2rem 3rem' }}>
                    {/* Video Player Section */}
                    {activeVideo ? (
                        (tutorial.isPremium && !isUnlocked) ? (
                            <div style={{
                                borderRadius: '24px',
                                overflow: 'hidden',
                                aspectRatio: '16/9',
                                background: 'linear-gradient(135deg, #1e1e2f 0%, #0a0a0a 100%)',
                                boxShadow: '0 25px 50px -12px rgba(0,0,0,0.5)',
                                border: '1px solid rgba(255,255,255,0.05)',
                                marginBottom: '1.5rem',
                                position: 'relative',
                                display: 'flex',
                                flexDirection: 'column',
                                alignItems: 'center',
                                justifyContent: 'center'
                            }}>
                                <Lock size={48} color="#fbbf24" style={{ marginBottom: '1rem' }} />
                                <h2 style={{ fontSize: '1.8rem', fontWeight: 800, marginBottom: '0.5rem' }}>Premium Series</h2>
                                <p style={{ color: 'rgba(255,255,255,0.6)', marginBottom: '2rem' }}>Unlock this complete series to access all lessons and resources.</p>
                                <button style={{
                                    background: 'linear-gradient(135deg, #fbbf24 0%, #f59e0b 100%)',
                                    color: '#000',
                                    border: 'none',
                                    padding: '0.8rem 2.5rem',
                                    borderRadius: '12px',
                                    fontWeight: 800,
                                    fontSize: '1rem',
                                    cursor: 'pointer',
                                    boxShadow: '0 10px 25px -5px rgba(251, 191, 36, 0.4)'
                                }} onClick={handleCheckout}>Unlock for ₹{tutorial.price} (1 Year Access)</button>
                            </div>
                        ) : (
                            <div style={{
                                borderRadius: '24px',
                                overflow: 'hidden',
                                aspectRatio: '16/9',
                                background: '#000',
                                boxShadow: '0 25px 50px -12px rgba(0,0,0,0.5)',
                                border: '1px solid rgba(255,255,255,0.05)',
                                marginBottom: '1.5rem',
                                position: 'relative'
                            }}>
                                <iframe
                                    width="100%"
                                    height="100%"
                                    src={`https://www.youtube.com/embed/${activeVideo.ytId}?rel=0&modestbranding=1&showinfo=0`}
                                    title={activeVideo.title}
                                    frameBorder="0"
                                    allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                                    allowFullScreen
                                    style={{ border: 'none' }}
                                ></iframe>
                            </div>
                        )
                    ) : (
                        <div style={{ aspectRatio: '16/9', background: '#111', borderRadius: '24px', display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: '1.5rem' }}>
                            <p style={{ color: 'rgba(255,255,255,0.4)' }}>No lessons available for this series.</p>
                        </div>
                    )}

                    {activeVideo && (
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '2rem' }}>
                            <div>
                                <h2 style={{ fontSize: '1.5rem', fontWeight: 800, marginBottom: '0.5rem' }}>{activeVideo.title}</h2>
                                <p style={{ color: 'rgba(255,255,255,0.6)', lineHeight: 1.6, maxWidth: '800px' }}>{activeVideo.description}</p>
                            </div>
                            <div style={{ display: 'flex', gap: '0.75rem' }}>
                                <button style={{
                                    background: 'rgba(255,255,255,0.03)',
                                    border: '1px solid rgba(255,255,255,0.1)',
                                    padding: '0.6rem 1rem',
                                    borderRadius: '10px',
                                    color: '#fff',
                                    cursor: 'pointer',
                                    display: 'flex',
                                    alignItems: 'center',
                                    gap: '0.5rem',
                                    fontSize: '0.9rem'
                                }}>
                                    <Share2 size={16} /> Share
                                </button>
                                <button style={{
                                    background: 'rgba(255,255,255,0.03)',
                                    border: '1px solid rgba(255,255,255,0.1)',
                                    padding: '0.6rem 1rem',
                                    borderRadius: '10px',
                                    color: '#fff',
                                    cursor: 'pointer',
                                    display: 'flex',
                                    alignItems: 'center',
                                    gap: '0.5rem',
                                    fontSize: '0.9rem'
                                }}>
                                    <BookOpen size={16} /> Resources
                                </button>
                            </div>
                        </div>
                    )}
                </main>

                {/* Sidebar Curriculum */}
                <aside style={{
                    width: '380px',
                    background: '#0a0a0a',
                    borderLeft: '1px solid rgba(255,255,255,0.05)',
                    padding: '2rem 1.5rem',
                    overflowY: 'auto',
                    height: 'calc(100vh - 56px)',
                    position: 'sticky',
                    top: '56px'
                }}>
                    <h3 style={{ fontSize: '1.1rem', fontWeight: 800, marginBottom: '1.5rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                        Curriculum <span style={{ fontSize: '0.8rem', opacity: 0.4 }}>({tutorial.lessons.length} Lessons)</span>
                    </h3>

                    <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                        {tutorial.lessons.sort((a, b) => a.order - b.order).map((video, index) => (
                            <div
                                key={video._id}
                                onClick={() => setActiveVideo(video)}
                                style={{
                                    padding: '1rem',
                                    borderRadius: '16px',
                                    background: activeVideo?._id === video._id ? 'rgba(99, 102, 241, 0.1)' : 'rgba(255,255,255,0.02)',
                                    border: `1px solid ${activeVideo?._id === video._id ? 'rgba(99, 102, 241, 0.2)' : 'rgba(255,255,255,0.05)'}`,
                                    cursor: 'pointer',
                                    transition: '0.2s cubic-bezier(0.165, 0.84, 0.44, 1)'
                                }}
                            >
                                <div style={{ display: 'flex', gap: '1rem', alignItems: 'flex-start' }}>
                                    <div style={{
                                        width: '28px',
                                        height: '28px',
                                        borderRadius: '8px',
                                        background: activeVideo?._id === video._id ? 'rgba(99, 102, 241, 0.2)' : 'rgba(255,255,255,0.05)',
                                        display: 'flex',
                                        alignItems: 'center',
                                        justifyContent: 'center',
                                        flexShrink: 0
                                    }}>
                                        {activeVideo?._id === video._id ? <Play size={14} color="#6366f1" fill="#6366f1" /> : (
                                            <span style={{ fontSize: '0.75rem', opacity: 0.4 }}>{index + 1}</span>
                                        )}
                                    </div>
                                    <div style={{ flex: 1 }}>
                                        <h5 style={{
                                            margin: '0 0 0.25rem 0',
                                            fontSize: '0.9rem',
                                            fontWeight: 700,
                                            color: activeVideo?._id === video._id ? '#fff' : 'rgba(255,255,255,0.8)'
                                        }}>{video.title}</h5>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', fontSize: '0.75rem', color: 'rgba(255,255,255,0.4)' }}>
                                            <span style={{ display: 'flex', alignItems: 'center', gap: '0.25rem' }}><Clock size={12} /> {video.duration || 'N/A'}</span>
                                            <span>•</span>
                                            <span>Video</span>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>

                    <div style={{ marginTop: '2.5rem', padding: '1.5rem', background: '#111', borderRadius: '20px', border: '1px solid rgba(255,255,255,0.05)' }}>
                        <h4 style={{ margin: '0 0 0.5rem 0', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                            <Award size={16} color="#f59e0b" /> Certificate
                        </h4>
                        <p style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.4)', lineHeight: 1.5, marginBottom: '1rem' }}>
                            {isEligibleForCertificate(tutorial.title)
                                ? "You've unlocked this professional series. Download your certificate of completion."
                                : "This series does not provide an official certificate. Focus on learning!"}
                        </p>
                        {isEligibleForCertificate(tutorial.title) ? (
                            <button
                                onClick={handleDownloadCertificate}
                                disabled={!isUnlocked && tutorial.isPremium}
                                style={{
                                    width: '100%',
                                    background: (!isUnlocked && tutorial.isPremium) ? 'rgba(255,255,255,0.05)' : 'linear-gradient(135deg, #6366f1, #a855f7)',
                                    border: 'none',
                                    padding: '0.8rem',
                                    borderRadius: '12px',
                                    color: '#fff',
                                    fontSize: '0.9rem',
                                    fontWeight: 700,
                                    cursor: (!isUnlocked && tutorial.isPremium) ? 'not-allowed' : 'pointer',
                                    transition: '0.3s'
                                }}
                            >
                                {(!isUnlocked && tutorial.isPremium) ? 'Unlock to Claim' : 'Claim Certificate'}
                            </button>
                        ) : (
                            <button style={{ width: '100%', background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.05)', padding: '0.6rem', borderRadius: '10px', color: 'rgba(255,255,255,0.2)', fontSize: '0.8rem', fontWeight: 600, cursor: 'not-allowed' }}>No Certificate</button>
                        )}
                    </div>
                </aside>
            </div>
        </div>
    );
};

export default TutorialPlayer;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { Search, Play, Lock, ChevronRight } from 'lucide-react';
import Loader from '../components/Loader';

const Tutorials = () => {
    const navigate = useNavigate();
    const [tutorials, setTutorials] = useState([]);
    const [unlockedTutorials, setUnlockedTutorials] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');

    useEffect(() => {
        const fetchTutorials = async () => {
            try {
                const token = localStorage.getItem('token');
                const res = await axios.get(`${import.meta.env.VITE_API_URL || 'https://dev2dev-backend.onrender.com'}/api/tutorials`, {
                    headers: { Authorization: `Bearer ${token}` }
                });
                setTutorials(res.data);

                // Get locally cached user info to check unlocked status
                const userString = localStorage.getItem('user');
                if (userString) {
                    try {
                        const user = JSON.parse(userString);
                        setUnlockedTutorials(user.unlockedTutorials || []);
                    } catch (e) { }
                }

                setLoading(false);
            } catch (err) {
                console.error('Error fetching tutorials:', err);
                setLoading(false);
            }
        };
        fetchTutorials();
    }, []);

    const filteredTutorials = tutorials.filter(t =>
        t.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
        t.category.toLowerCase().includes(searchTerm.toLowerCase())
    );

    if (loading) return <Loader text="Unlocking Premium Knowledge..." />;

    return (
        <div style={{ minHeight: '100vh', background: '#0a0a0a', color: '#fff', padding: '2rem 3rem' }}>
            {/* Header section */}
            <div style={{ marginBottom: '3rem', display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end' }}>
                <div>
                    <h1 style={{ fontSize: '2.5rem', fontWeight: 900, marginBottom: '0.5rem', background: 'linear-gradient(to right, #fff, #6366f1)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>
                        Premium Tutorials
                    </h1>
                    <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: '1.1rem' }}>Learn from industry experts with our curated video series.</p>
                </div>
                <div style={{ position: 'relative', width: '300px' }}>
                    <Search size={18} style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', color: 'rgba(255,255,255,0.3)' }} />
                    <input
                        type="text"
                        placeholder="Search series..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        style={{
                            width: '100%',
                            background: 'rgba(255,255,255,0.03)',
                            border: '1px solid rgba(255,255,255,0.1)',
                            borderRadius: '12px',
                            padding: '0.75rem 1rem 0.75rem 2.8rem',
                            color: '#fff',
                            outline: 'none'
                        }}
                    />
                </div>
            </div>

            {/* Tutorials Grid */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(350px, 1fr))', gap: '2rem' }}>
                {filteredTutorials.map((tutorial) => (
                    <div
                        key={tutorial._id}
                        onClick={() => navigate(`/tutorials/${tutorial._id}`)}
                        className="tutorial-card"
                        style={{
                            background: 'rgba(255,255,255,0.02)',
                            borderRadius: '24px',
                            border: '1px solid rgba(255,255,255,0.05)',
                            overflow: 'hidden',
                            cursor: 'pointer',
                            transition: 'all 0.3s ease'
                        }}
                    >
                        <div style={{ position: 'relative', height: '200px' }}>
                            <img src={tutorial.thumbnail} alt={tutorial.title} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                            <div style={{ position: 'absolute', top: '12px', right: '12px', background: 'rgba(99, 102, 241, 0.9)', color: '#fff', padding: '4px 12px', borderRadius: '20px', fontSize: '0.75rem', fontWeight: 700 }}>
                                {tutorial.category}
                            </div>
                            <div style={{ position: 'absolute', bottom: '12px', left: '12px', background: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(4px)', color: '#fff', padding: '4px 8px', borderRadius: '8px', fontSize: '0.75rem', display: 'flex', alignItems: 'center', gap: '4px' }}>
                                <Play size={12} fill="white" /> {tutorial.lessons.length} Lessons
                            </div>
                        </div>
                        <div style={{ padding: '1.5rem' }}>
                            <h3 style={{ fontSize: '1.25rem', fontWeight: 800, marginBottom: '0.75rem' }}>{tutorial.title}</h3>
                            <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: '0.9rem', lineHeight: 1.5, marginBottom: '1.5rem', display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical', overflow: 'hidden' }}>
                                {tutorial.description}
                            </p>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', color: (tutorial.isPremium && !unlockedTutorials.includes(tutorial._id)) ? '#fbbf24' : '#6366f1', fontSize: '0.9rem', fontWeight: 700 }}>
                                    {(tutorial.isPremium && !unlockedTutorials.includes(tutorial._id)) ? <Lock size={16} /> : <Play size={16} />}
                                    {(tutorial.isPremium && !unlockedTutorials.includes(tutorial._id)) ? `Unlock for ₹${tutorial.price} / Year` : 'Start Learning'} <ChevronRight size={18} />
                                </div>
                                <div style={{ color: 'rgba(255,255,255,0.3)', fontSize: '0.8rem' }}>
                                    Updated {new Date(tutorial.createdAt).toLocaleDateString()}
                                </div>
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            <style>{`
                .tutorial-card:hover {
                    transform: translateY(-8px);
                    border-color: rgba(99, 102, 241, 0.3);
                    background: rgba(255,255,255,0.04);
                    box-shadow: 0 20px 40px -20px rgba(0,0,0,0.5);
                }
                .loader {
                    border: 3px solid rgba(255,255,255,0.1);
                    border-top: 3px solid #6366f1;
                    border-radius: 50%;
                    width: 40px;
                    height: 40px;
                    animation: spin 1s linear infinite;
                }
                @keyframes spin {
                    0% { transform: rotate(0deg); }
                    100% { transform: rotate(360deg); }
                }
            `}</style>
        </div>
    );
};

export default Tutorials;
